        // 云端全自动拉取同步
        async function syncFromCloud() {
            try {
                let { data, error } = await supabaseClient
                    .from('sync_store')
                    .select('*')
                    .eq('sync_id', SY_ROOM_ID)
                    .single();

                if (data) {
                    products = data.products || products;
                    orders = data.orders || orders;
                    if (data.users && Array.isArray(data.users)) {
                        users = data.users;
                        localStorage.setItem('sg_users', JSON.stringify(users));
                    }
                    localStorage.setItem('sg_products', JSON.stringify(products));
                    localStorage.setItem('sg_orders', JSON.stringify(orders));
                    
                    renderProductTable();
                    renderCartTable();
                    updateReportDashboard();
                    renderUserTable();
                    applyAuthUI();
                }
            } catch (e) {}
        }

        // 云端全自动推送同步
        async function pushToCloud() {
            if (!supabaseClient) return;
            try {
                const payload = { sync_id: SY_ROOM_ID, products, orders, users, updated_at: new Date() };
                const { error } = await supabaseClient.from('sync_store').upsert(payload);
                if (error) {
                    await supabaseClient.from('sync_store').upsert({ sync_id: SY_ROOM_ID, products, orders, updated_at: new Date() });
                }
            } catch (e) {}
        }


        function hasPermission(permission) {
            if (!currentUser) return false;
            return (ROLE_PERMISSIONS[currentUser.role] || []).includes(permission);
        }

        function requirePermission(permission, message) {
            if (hasPermission(permission)) return true;
            alert(message || '当前账号没有权限执行此操作。');
            return false;
        }

        function loginUser(e) {
            e.preventDefault();
            const username = document.getElementById('login-username').value.trim();
            const password = document.getElementById('login-password').value;
            const user = users.find(u => u.username === username && u.password === password && u.status === 'active');
            const err = document.getElementById('login-error');
            if (!user) {
                err.innerText = '账号、密码错误，或该账号已停用。';
                err.classList.remove('hidden');
                return;
            }
            user.lastLogin = new Date().toLocaleString();
            localStorage.setItem('sg_users', JSON.stringify(users));
            currentUser = { id: user.id, username: user.username, displayName: user.displayName, role: user.role };
            localStorage.setItem('sg_current_user', JSON.stringify(currentUser));
            err.classList.add('hidden');
            applyAuthUI();
            renderUserTable();
            pushToCloud();
        }

        function logoutUser() {
            currentUser = null;
            localStorage.removeItem('sg_current_user');
            cart = [];
            renderCartTable();
            applyAuthUI();
        }

        function applyAuthUI() {
            const loggedIn = !!currentUser;
            document.getElementById('login-modal').classList.toggle('hidden', loggedIn);
            document.getElementById('btn-logout').classList.toggle('hidden', !loggedIn);
            document.getElementById('current-user-badge').classList.toggle('hidden', !loggedIn);
            if (loggedIn) document.getElementById('current-user-name').innerText = `${currentUser.displayName} · ${ROLE_LABELS[currentUser.role] || currentUser.role}`;

            document.querySelectorAll('[data-permission]').forEach(el => {
                el.classList.toggle('hidden', !hasPermission(el.dataset.permission));
            });

            const availableTabs = ['product-tab', 'sales-tab', 'report-tab', 'user-tab'].filter(tab => {
                if (tab === 'product-tab') return hasPermission('product_manage');
                if (tab === 'sales-tab') return hasPermission('sales_checkout');
                if (tab === 'report-tab') return hasPermission('report_view');
                if (tab === 'user-tab') return hasPermission('user_manage');
            });
            if (loggedIn) {
                const active = document.querySelector('.tab-content:not(.hidden)');
                if (!active || !availableTabs.includes(active.id)) switchTab(availableTabs[0] || 'sales-tab');
            }
        }

