function filterSearchProducts() {
            const query = document.getElementById('search-prod-input').value.trim().toLowerCase();
            const panel = document.getElementById('search-results-panel');
            
            if (!query) {
                panel.innerHTML = ''; panel.classList.add('hidden'); return;
            }
            
            const matched = products.filter(p => 
                p.name.toLowerCase().includes(query) || p.id.toLowerCase().includes(query)
            );
            
            if (matched.length === 0) {
                panel.innerHTML = `<div class="p-3 text-xs text-slate-500 text-center">未检索到匹配的商品资产</div>`;
                panel.classList.remove('hidden'); return;
            }
            
            panel.innerHTML = matched.map(p => `
                <div onclick="selectSearchProduct('${p.id}')" class="flex items-center justify-between p-2 hover:bg-slate-700/80 cursor-pointer transition duration-150 group">
                    <div class="flex items-center space-x-2.5 truncate">
                        <img src="${p.image}" class="w-7 h-7 object-cover rounded border border-slate-600 flex-shrink-0">
                        <div class="truncate">
                            <p class="text-xs font-semibold text-slate-200 truncate group-hover:text-orange-300">${p.name}</p>
                            <p class="text-[10px] font-mono text-orange-500/80">${p.id}</p>
                        </div>
                    </div>
                    <span class="text-xs font-bold text-orange-300 ml-2 bg-slate-900/40 px-1.5 py-0.5 rounded border border-slate-700">￥${p.price.toFixed(2)}</span>
                </div>
            `).join('');
            panel.classList.remove('hidden');
        }

        function selectSearchProduct(id) {
            handleScannedProductId(id); 
            document.getElementById('search-prod-input').value = ''; 
            document.getElementById('search-results-panel').classList.add('hidden'); 
        }

        // 2. B方式：下拉菜单的动态渲染与同步
        function updateMockScannerDropdown() {
            const dropdown = document.getElementById('mock-scanner-dropdown');
            if (!dropdown) return;
            dropdown.innerHTML = '<option value="">选择商品</option>' + 
                products.map(p => `<option value="${p.id}">${p.name} (￥${p.price.toFixed(2)})</option>`).join('');
        }

        // 3. B方式：点击将下拉选项塞进购物车
        function addDropdownProductToCart() {
            const dropdown = document.getElementById('mock-scanner-dropdown');
            const selectedId = dropdown.value;
            if (!selectedId) {
                alert("请先从下拉列表中选择一款商品！"); return;
            }
            handleScannedProductId(selectedId); 
            dropdown.value = ""; 
        }

        // 监听外部点击自动隐藏联想面板
        document.addEventListener('click', function(e) {
            const panel = document.getElementById('search-results-panel');
            const input = document.getElementById('search-prod-input');
            if (panel && e.target !== input && !panel.contains(e.target)) {
                panel.classList.add('hidden');
            }
        });

        function updateCartQty(index, amt) {
            if (!cart[index]) return;
            cart[index].quantity = Math.max(1, parseInt(cart[index].quantity || 1, 10) + amt);
            renderCartTable();
        }

        function setCartQty(index, value) {
            if (!cart[index]) return;
            let qty = parseInt(value, 10);
            if (!Number.isInteger(qty) || qty < 1) qty = 1;
            cart[index].quantity = qty;
            renderCartTable();
        }
        function clearCart() { cart = []; renderCartTable(); }

        // 重新定义渲染逻辑，加入折扣下拉菜单
function renderCartTable() {
    const tbody = document.getElementById('cart-table-body');
    if(!tbody) return;
    
    // 如果购物车为空
    if(cart.length === 0) {
        tbody.innerHTML = `<tr><td colspan="6" class="p-6 text-center text-slate-500">结算柜台空，请使用手机摄像头扫码或手动选择单品录入</td></tr>`;
        document.getElementById('cart-total-amount').innerText = "￥0.00"; 
        return;
    }

    let total = 0;
    tbody.innerHTML = cart.map((item, idx) => {
        // 获取折扣，如果没有则默认为 1.0 (100%)
        const discount = item.discount || 1.0;
        const subtotal = item.product.price * item.quantity * discount; 
        total += subtotal;

        return `
            <tr class="border-b border-slate-700/50">
                <td class="p-3 font-medium">${item.product.name}</td>
                <td class="p-3 text-slate-400">￥${item.product.price.toFixed(2)}</td>
                <td class="p-3">
                    <select onchange="updateCartDiscount(${idx}, this.value)" class="bg-slate-900 border border-slate-600 rounded text-xs px-1 text-orange-300">
                        ${generateDiscountOptions(discount)}
                    </select>
                </td>
                <td class="p-3">
                    <div class="flex items-center space-x-1.5">
                        <button onclick="updateCartQty(${idx}, -1)" class="w-6 h-6 rounded bg-slate-700 flex items-center justify-center hover:bg-slate-600">-</button>
                        <input type="number" min="1" step="1" inputmode="numeric" pattern="[0-9]*" value="${item.quantity}" onchange="setCartQty(${idx}, this.value)" onblur="setCartQty(${idx}, this.value)" onkeydown="if(event.key==='Enter'){this.blur();}" class="w-16 bg-slate-950 border border-slate-600 rounded px-1 py-0.5 text-center font-bold text-slate-100 focus:outline-none focus:border-orange-500" title="可手动输入整数数量">
                        <button onclick="updateCartQty(${idx}, 1)" class="w-6 h-6 rounded bg-slate-700 flex items-center justify-center hover:bg-slate-600">+</button>
                    </div>
                </td>
                <td class="p-3 text-orange-300 font-bold">￥${subtotal.toFixed(2)}</td>
                <td class="p-3 text-center"><button onclick="cart.splice(${idx},1); renderCartTable();" class="text-red-400"><i class="fa-regular fa-trash-can"></i></button></td>
            </tr>
        `;
    }).join('');
    document.getElementById('cart-total-amount').innerText = `￥${total.toFixed(2)}`;
}

// 生成 30%-100% 的折扣选项
function generateDiscountOptions(selected) {
    let html = '';
    for (let i = 30; i <= 100; i += 5) {
        const val = i / 100;
        html += `<option value="${val}" ${selected == val ? 'selected' : ''}>${i}%</option>`;
    }
    return html;
}

// 修改折扣并自动刷新界面
function updateCartDiscount(idx, val) {
    cart[idx].discount = parseFloat(val);
    renderCartTable();
} 
