        function handleSort(field) {
            if (sortField === field) { sortDirection = sortDirection === 'asc' ? 'desc' : 'asc'; }
            else { sortField = field; sortDirection = 'desc'; }
            renderLedgerTable();
        }

        function renderLedgerTable() {
            const tbody = document.getElementById('ledger-table-body');
            if(!tbody || orders.length === 0) { if(tbody) tbody.innerHTML='<tr><td colspan="5" class="p-4 text-center">暂无账单流向</td></tr>'; return; }

            ['id', 'date', 'total'].forEach(f => {
                const el = document.getElementById(`sort-icon-${f}`);
                if(el) el.innerHTML = f === sortField ? (sortDirection === 'asc' ? '↑' : '↓') : '↕';
            });

            const sortedOrders = [...orders].sort((a, b) => {
                let valA = a[sortField], valB = b[sortField];
                if (sortField === 'date') return sortDirection === 'asc' ? new Date(valA) - new Date(valB) : new Date(valB) - new Date(valA);
                if (sortField === 'total') return sortDirection === 'asc' ? valA - valB : valB - valA;
                return sortDirection === 'asc' ? valA.localeCompare(valB) : valB.localeCompare(valA);
            });

            tbody.innerHTML = sortedOrders.map(order => {
                const itemsSummary = order.items.map(i => `${i.name} (x${i.quantity})`).join('、');
                return `
                    <tr class="border-b border-slate-800 hover:bg-slate-800/40 transition">
                        <td class="p-3 font-mono font-bold text-orange-300">${order.id}</td>
                        <td class="p-3 text-slate-300 font-mono">${order.date}</td>
                        <td class="p-3 text-slate-400 max-w-xs truncate" title="${itemsSummary}">${itemsSummary}</td>
                        <td class="p-3 font-bold text-orange-300">￥${order.total.toFixed(2)}</td>
                        <td class="p-3 text-center"><button onclick="reviewHistoryReceipt('${order.id}')" class="bg-slate-700 px-2 py-0.5 rounded text-orange-300">补打</button></td>
                    </tr>
                `;
            }).join('');
        }

        function calculateAndRenderTop10() {
            const now = new Date();
            const todayStr = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;
            const monthStr = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
            const yearStr = `${now.getFullYear()}`;

            document.getElementById('label-today').innerText = todayStr;
            document.getElementById('label-month').innerText = monthStr;
            document.getElementById('label-year').innerText = yearStr + "年";

            function getTopProductsByFilter(filterFn) {
                let counts = {};
                orders.filter(filterFn).forEach(o => o.items.forEach(i => counts[i.name] = (counts[i.name] || 0) + i.quantity));
                return Object.entries(counts).map(([name, qty]) => ({ name, qty })).sort((a, b) => b.qty - a.qty).slice(0, 10);
            }

            function generateRankHtml(list, color) {
                if(list.length === 0) return `<div class="text-slate-600 text-center py-4">暂无交易</div>`;
                return list.map((item, idx) => `
                    <li class="flex items-center justify-between p-1 rounded">
                        <span class="truncate"><span class="text-slate-500 mr-1">${idx+1}.</span>${item.name}</span>
                        <span class="font-bold ${color}">${item.qty}件</span>
                    </li>
                `).join('');
            }

            document.getElementById('top-day-list').innerHTML = generateRankHtml(getTopProductsByFilter(o => o.date === todayStr), 'text-orange-300');
            document.getElementById('top-month-list').innerHTML = generateRankHtml(getTopProductsByFilter(o => o.date.startsWith(monthStr)), 'text-orange-300');
            document.getElementById('top-year-list').innerHTML = generateRankHtml(getTopProductsByFilter(o => o.date.startsWith(yearStr)), 'text-amber-400');
        }

