function rebuildProductLookupMap() {
            productLookupMap = new Map(products.map(p => [String(p.id).trim(), p]));
        }

        function setScanStatus(text, tone = 'info') {
            const el = document.getElementById('scan-status');
            if (!el) return;
            el.classList.remove('hidden', 'text-slate-400', 'text-orange-300', 'text-red-400', 'text-emerald-400');
            const toneClass = tone === 'ok' ? 'text-emerald-400' : tone === 'warn' ? 'text-orange-300' : tone === 'err' ? 'text-red-400' : 'text-slate-400';
            el.classList.add(toneClass);
            el.innerText = text;
        }

        async function startCameraScan() {
            try {
                rebuildProductLookupMap();
                document.getElementById('reader-placeholder').classList.add('hidden');
                document.getElementById('btn-start-scan').classList.add('hidden');
                document.getElementById('btn-stop-scan').classList.remove('hidden');
                document.getElementById('btn-torch').classList.remove('hidden');
                document.getElementById('btn-torch').classList.add('flex');
                setScanStatus('正在启动后置摄像头，建议将二维码置于橙色框中央。');

                html5Qrcode = new Html5Qrcode("reader", { verbose: false });
                const config = {
                    fps: 7,                         // 降低解码频率，手机更省电且减少卡顿
                    disableFlip: true,              // 后置摄像头不需要镜像识别
                    aspectRatio: 1.0,
                    qrbox: (width, height) => {     // 只识别中心区域，避免整帧扫描
                        const minEdge = Math.min(width, height);
                        const qrboxSize = Math.floor(minEdge * 0.68);
                        return { width: qrboxSize, height: qrboxSize };
                    },
                    experimentalFeatures: { useBarCodeDetectorIfSupported: true },
                    videoConstraints: {
                        facingMode: { ideal: "environment" },
                        width: { ideal: 1280 },
                        height: { ideal: 720 },
                        focusMode: "continuous"
                    }
                };

                await html5Qrcode.start(
                    { facingMode: { ideal: "environment" } },
                    config,
                    (decodedText) => { handleScannedProductId(decodedText); },
                    () => {}
                );
                setScanStatus('扫描中：已启用中心区域高速识别与重复扫码防抖。', 'ok');
            } catch (err) {
                alert("无法激活手机摄像头。请检查权限或尝试使用 HTTPS 域名安全访问。");
                stopCameraScan();
            }
        }

        function stopCameraScan() {
            if (html5Qrcode && html5Qrcode.isScanning) {
                html5Qrcode.stop().then(() => { resetScanUI(); }).catch(() => { resetScanUI(); });
            } else { resetScanUI(); }
        }

        function resetScanUI() {
            document.getElementById('reader-placeholder').classList.remove('hidden');
            document.getElementById('btn-start-scan').classList.remove('hidden');
            document.getElementById('btn-stop-scan').classList.add('hidden');
            document.getElementById('btn-torch').classList.add('hidden');
            document.getElementById('btn-torch').classList.remove('flex');
            document.getElementById('reader').innerHTML = "";
            document.getElementById('apple-focus-box').classList.remove('active');
            const status = document.getElementById('scan-status');
            if (status) status.classList.add('hidden');
            lastScannedId = "";
            torchOn = false;
        }

        function getActiveVideoTrack() {
            const video = document.querySelector('#reader video');
            const stream = video && video.srcObject;
            return stream && stream.getVideoTracks ? stream.getVideoTracks()[0] : null;
        }

        async function toggleTorch() {
            const track = getActiveVideoTrack();
            if (!track) return setScanStatus('尚未获取到摄像头轨道。', 'warn');
            const caps = track.getCapabilities ? track.getCapabilities() : {};
            if (!caps.torch) return setScanStatus('当前设备或浏览器不支持手电筒控制。', 'warn');
            try {
                torchOn = !torchOn;
                await track.applyConstraints({ advanced: [{ torch: torchOn }] });
                setScanStatus(torchOn ? '手电筒已开启，暗光环境识别会更稳定。' : '手电筒已关闭。', 'ok');
                const btn = document.getElementById('btn-torch');
                btn.classList.toggle('bg-orange-500', torchOn);
                btn.classList.toggle('text-slate-950', torchOn);
            } catch (e) {
                setScanStatus('手电筒切换失败，请尝试重新开启摄像头。', 'err');
            }
        }

        async function triggerTapToFocus(event) {
            const container = document.getElementById('interactive-reader-container');
            const rect = container.getBoundingClientRect();
            const x = event.clientX - rect.left; const y = event.clientY - rect.top;

            const focusBox = document.getElementById('apple-focus-box');
            focusBox.style.left = `${x}px`; focusBox.style.top = `${y}px`;
            focusBox.classList.remove('active'); void focusBox.offsetWidth; focusBox.classList.add('active');

            const track = getActiveVideoTrack();
            try {
                if (track && track.applyConstraints) await track.applyConstraints({ advanced: [{ focusMode: 'continuous' }] });
                else if (html5Qrcode && html5Qrcode.isScanning) await html5Qrcode.applyVideoConstraints({ facingMode: "environment" });
                setScanStatus('已尝试触发连续对焦，请保持二维码位于中心框内。');
            } catch (err) {}
            setTimeout(() => {
                if (focusBox.style.left === `${x}px` && focusBox.style.top === `${y}px`) focusBox.classList.remove('active');
            }, 1000);
        }

        function handleScannedProductId(prodId) {
            if (!requirePermission('sales_checkout', '当前账号无权进行收银操作。')) return;
            const now = Date.now();
            const cleanId = String(prodId || '').trim();
            if (!cleanId) return;
            if (cleanId === lastScannedId && (now - lastScannedTime < 1800)) return;
            if (now - lastScannedTime < 450) return;

            if (!productLookupMap || productLookupMap.size !== products.length) rebuildProductLookupMap();
            const product = productLookupMap.get(cleanId);
            lastScannedId = cleanId;
            lastScannedTime = now;
            if (!product) {
                setScanStatus('未找到商品码：' + cleanId, 'err');
                return;
            }
            if ((product.stock ?? 0) <= 0 && !confirm('该商品库存为 0，仍要加入购物车吗？')) return;

            const existing = cart.find(item => item.product.id === cleanId);
            if (existing) { existing.quantity = Math.max(1, parseInt(existing.quantity || 1, 10)) + 1; }
            else { cart.push({ product, quantity: 1, discount: 1.0 }); }

            renderCartTable(); playBeepSound();
            setScanStatus(`已加入：${product.name}`, 'ok');

            const scanZone = document.getElementById('interactive-reader');
            scanZone.classList.add('border-orange-500', 'shadow-[0_0_20px_rgba(249,115,22,0.45)]');
            setTimeout(() => { scanZone.classList.remove('border-orange-500', 'shadow-[0_0_20px_rgba(249,115,22,0.45)]'); }, 450);
        }

        function playBeepSound() {
            try {
                const audioCtx = new (window.AudioContext || window.webkitAudioContext)();
                const oscillator = audioCtx.createOscillator(); const gainNode = audioCtx.createGain();
                oscillator.connect(gainNode); gainNode.connect(audioCtx.destination);
                oscillator.type = 'sine'; oscillator.frequency.setValueAtTime(1150, audioCtx.currentTime);
                gainNode.gain.setValueAtTime(0.12, audioCtx.currentTime);
                oscillator.start(); oscillator.stop(audioCtx.currentTime + 0.09);
            } catch (e) {}
        }

        // ===================== 安全与经营增强补丁 v2 =====================
        let auditLogs = JSON.parse(localStorage.getItem('sg_audit_logs') || '[]');
        let syncVersion = parseInt(localStorage.getItem('sg_sync_version') || '0', 10);
        let loginFailures = JSON.parse(localStorage.getItem('sg_login_failures') || '{}');
        const EXTRA_PERMISSIONS = ['product_delete', 'order_refund', 'data_reset', 'data_export', 'audit_view', 'audit_delete'];
        ROLE_PERMISSIONS.admin = ['product_manage','sales_checkout','report_view','user_manage','product_delete','order_refund','data_reset','data_export','audit_view','audit_delete'];
        ROLE_PERMISSIONS.manager = ['product_manage','sales_checkout','report_view','data_export','audit_view'];
        ROLE_PERMISSIONS.cashier = ['sales_checkout'];
        ROLE_PERMISSIONS.viewer = ['report_view','audit_view'];

/* ===== END assets/js/modules/50-scanner.js ===== */


