        async function hashPassword(password, salt){
            salt = salt || Array.from(crypto.getRandomValues(new Uint8Array(12))).map(b=>b.toString(16).padStart(2,'0')).join('');
            if (window.crypto && crypto.subtle) {
                const data = new TextEncoder().encode(salt + '|' + password);
                const buf = await crypto.subtle.digest('SHA-256', data);
                const hash = Array.from(new Uint8Array(buf)).map(b=>b.toString(16).padStart(2,'0')).join('');
                return {salt, hash};
            }
            let h = 0; for (const ch of salt + '|' + password) h = Math.imul(31, h) + ch.charCodeAt(0) | 0;
            return {salt, hash: String(h)};
        }
        async function verifyPassword(user, password){
            if (user.passwordHash && user.passwordSalt) {
                const hp = await hashPassword(password, user.passwordSalt); return hp.hash === user.passwordHash;
            }
            return user.password === password;
        }
        async function migrateUsersSecurity(){
            let changed = false;
            for (const u of users) {
                if (u.password && !u.passwordHash) { const hp = await hashPassword(u.password); u.passwordSalt = hp.salt; u.passwordHash = hp.hash; delete u.password; changed = true; }
                if (!u.permissions) u.permissions = ROLE_PERMISSIONS[u.role] || [];
            }
            if (changed) { saveAllLocal(); await pushToCloud(); }
        }
        const oldOnLoad = window.onload;
        window.onload = async function(){
            if (oldOnLoad) await oldOnLoad();
            await migrateUsersSecurity();
            products.forEach(p => { if (p.stock === undefined) p.stock = 0; if (p.lowStock === undefined) p.lowStock = 5; if (!p.updatedAt) p.updatedAt = new Date().toISOString(); });
            orders.forEach(o => { if (!o.operator && o.items && o.items[0]) o.operator = o.items[0].operator || ''; });
            saveAllLocal(); renderProductTable(); renderAuditTable(); updateReportDashboard();
        };
        hasPermission = function(permission){
            if (!currentUser) return false;
            const live = users.find(u => u.id === currentUser.id);
            const perms = live && Array.isArray(live.permissions) ? live.permissions : (ROLE_PERMISSIONS[currentUser.role] || []);
            return perms.includes(permission) || (ROLE_PERMISSIONS[currentUser.role] || []).includes(permission);
        };
        loginUser = async function(e){
            e.preventDefault();
            const username = document.getElementById('login-username').value.trim();
            const password = document.getElementById('login-password').value;
            const err = document.getElementById('login-error');
            const fail = loginFailures[username] || {count:0, lockedUntil:0};
            if (Date.now() < fail.lockedUntil) { err.innerText='登录失败次数过多，请 5 分钟后再试。'; err.classList.remove('hidden'); return; }
            const user = users.find(u => u.username === username && u.status === 'active');
            if (!user || !(await verifyPassword(user, password))) {
                fail.count = (fail.count || 0) + 1; if (fail.count >= 5) { fail.lockedUntil = Date.now() + 5*60*1000; fail.count = 0; }
                loginFailures[username] = fail; localStorage.setItem('sg_login_failures', JSON.stringify(loginFailures));
                err.innerText = '账号、密码错误，或该账号已停用。'; err.classList.remove('hidden'); addAudit('登录失败', username, '账号或密码错误'); return;
            }
            loginFailures[username] = {count:0, lockedUntil:0}; localStorage.setItem('sg_login_failures', JSON.stringify(loginFailures));
            if (user.password) { const hp = await hashPassword(password); user.passwordSalt = hp.salt; user.passwordHash = hp.hash; delete user.password; }
            user.lastLogin = nowText(); user.updatedAt = new Date().toISOString();
            currentUser = { id: user.id, username: user.username, displayName: user.displayName, role: user.role };
            localStorage.setItem('sg_current_user', JSON.stringify(currentUser)); saveAllLocal(); err.classList.add('hidden');
            addAudit('登录成功', username, ''); applyAuthUI(); renderUserTable(); await pushToCloud();
        };
        saveUserAccount = async function(e){
            e.preventDefault(); if (!requirePermission('user_manage')) return;
            const editId = document.getElementById('u-edit-id').value;
            const username = document.getElementById('u-username').value.trim();
            const displayName = document.getElementById('u-display-name').value.trim();
            const password = document.getElementById('u-password').value;
            const role = document.getElementById('u-role').value; const status = document.getElementById('u-status').value;
            if (!editId && password.length < 6) return alert('新用户密码至少 6 位。');
            if (!editId && users.some(u => u.username === username)) return alert('该登录账号已存在。');
            if (editId) {
                const u = users.find(x => x.id === editId); if (!u) return;
                u.displayName=displayName; u.role=role; u.status=status; u.permissions=ROLE_PERMISSIONS[role] || []; u.updatedAt=new Date().toISOString();
                if (password) { if(password.length<6) return alert('新密码至少 6 位。'); const hp=await hashPassword(password); u.passwordSalt=hp.salt; u.passwordHash=hp.hash; delete u.password; }
                if (currentUser && currentUser.id === u.id) { currentUser = {id:u.id, username:u.username, displayName:u.displayName, role:u.role}; localStorage.setItem('sg_current_user', JSON.stringify(currentUser)); }
                addAudit('编辑用户', u.username, `角色：${ROLE_LABELS[role] || role}，状态：${status}`);
            } else {
                const hp=await hashPassword(password);
                users.push({id:'U-'+Date.now(), username, passwordSalt:hp.salt, passwordHash:hp.hash, displayName, role, permissions:ROLE_PERMISSIONS[role]||[], status, createdAt:new Date().toISOString(), updatedAt:new Date().toISOString(), lastLogin:''});
                addAudit('新增用户', username, `角色：${ROLE_LABELS[role] || role}`);
            }
            syncVersion++; saveAllLocal(); resetUserForm(); renderUserTable(); applyAuthUI(); await pushToCloud();
        };
        deleteUserAccount = async function(id){
            if (!requirePermission('user_manage')) return;
            if (currentUser && currentUser.id === id) return alert('不能删除当前登录账号。');
            if (users.filter(u=>u.status==='active').length <= 1) return alert('至少保留一个启用账号。');
            const u = users.find(x=>x.id===id); if (!u) return;
            if (!confirm('确定删除此用户吗？')) return;
            users = users.filter(x => x.id !== id); syncVersion++; saveAllLocal(); addAudit('删除用户', u.username, ''); renderUserTable(); await pushToCloud();
        };
        changeOwnPassword = async function(e){
            e.preventDefault(); if(!currentUser) return;
            const oldP=document.getElementById('own-old-password').value, newP=document.getElementById('own-new-password').value;
            if(newP.length < 6) return alert('新密码至少 6 位。');
            const u=users.find(x=>x.id===currentUser.id); if(!u || !(await verifyPassword(u, oldP))) return alert('当前密码不正确。');
            const hp=await hashPassword(newP); u.passwordSalt=hp.salt; u.passwordHash=hp.hash; delete u.password; u.updatedAt=new Date().toISOString();
            syncVersion++; saveAllLocal(); e.target.reset(); addAudit('修改密码', u.username, '当前账号自行修改'); await pushToCloud(); alert('密码已更新。');
        };
        const oldRenderUserTable = renderUserTable;
        renderUserTable = function(){ oldRenderUserTable(); renderAuditTable(); };
        const oldOpenEditModal = openEditModal;
        openEditModal = function(id){ oldOpenEditModal(id); const p=products.find(x=>x.id===id); if(p){ document.getElementById('edit-p-stock').value = p.stock || 0; document.getElementById('edit-p-low-stock').value = p.lowStock ?? 5; }};
        saveProduct = async function(e){
            if (!requirePermission('product_manage', '当前账号无权新增商品。')) return; e.preventDefault();
            const name=document.getElementById('p-name').value; const price=parseFloat(document.getElementById('p-price').value); const designer=document.getElementById('p-designer').value || '未署名';
            const stock=parseInt(document.getElementById('p-stock').value || '0',10); const lowStock=parseInt(document.getElementById('p-low-stock').value || '5',10);
            let image=currentImageBase64 || 'https://images.unsplash.com/photo-1505740420928-5e560c06d30e?w=100'; const id='SG-'+Math.random().toString(36).substring(2,10).toUpperCase();
            products.push({id,name,price,designer,image,stock,lowStock,createdAt:new Date().toISOString(),updatedAt:new Date().toISOString()}); syncVersion++; saveAllLocal(); addAudit('新增商品', id, `${name} / 库存 ${stock}`);
            document.getElementById('qrcode-canvas').innerHTML=''; qrGenerator=new QRCode(document.getElementById('qrcode-canvas'), {text:id,width:140,height:140}); document.getElementById('qr-prod-id').innerText=`商品特征码: ${id}`; document.getElementById('btn-download-qr').disabled=false; document.getElementById('btn-download-qr').className='w-full bg-orange-500 text-slate-950 font-bold py-2 rounded-lg text-xs shadow-lg';
            renderProductTable(); document.getElementById('product-form').reset(); clearUploadedImage(null,'add'); await pushToCloud();
        };
        saveEditProduct = async function(e){
            if (!requirePermission('product_manage', '当前账号无权编辑商品。')) return; e.preventDefault();
            const idx=products.findIndex(p=>p.id===editingProductId); if(idx===-1) return;
            products[idx].name=document.getElementById('edit-p-name').value; products[idx].price=parseFloat(document.getElementById('edit-p-price').value); products[idx].designer=document.getElementById('edit-p-designer').value; products[idx].image=currentEditImageBase64;
            products[idx].stock=parseInt(document.getElementById('edit-p-stock').value||'0',10); products[idx].lowStock=parseInt(document.getElementById('edit-p-low-stock').value||'5',10); products[idx].updatedAt=new Date().toISOString();
            syncVersion++; saveAllLocal(); addAudit('编辑商品', products[idx].id, `${products[idx].name} / 库存 ${products[idx].stock}`); renderProductTable(); renderCartTable(); closeEditModal(); await pushToCloud();
        };
        deleteProduct = async function(id){
            if (!requirePermission('product_delete', '当前账号无权删除商品。')) return;
            const p=products.find(x=>x.id===id); if (!p) return; if(confirm('确定要彻底注销此项核心物资商品吗？')) { products=products.filter(x=>x.id!==id); syncVersion++; saveAllLocal(); addAudit('删除商品', id, p.name); renderProductTable(); await pushToCloud(); }
        };
        renderProductTable = function(){
            const tbody=document.getElementById('product-table-body'); if(!tbody) return;
            tbody.innerHTML = products.map(p => { const stock=p.stock ?? 0, low=p.lowStock ?? 5; const warn=stock<=low; return `<tr class="border-b border-slate-800 hover:bg-slate-800/40 transition"><td class="p-3"><img src="${p.image}" class="w-8 h-8 object-cover rounded border border-slate-600"></td><td class="p-3 font-mono text-orange-300 font-bold">${p.id}</td><td class="p-3 font-medium text-slate-200">${p.name}</td><td class="p-3 text-slate-400">${p.designer}</td><td class="p-3 font-bold text-slate-300">￥${p.price.toFixed(2)}</td><td class="p-3"><span class="px-2 py-0.5 rounded border ${warn?'bg-red-950 text-red-400 border-red-900':'bg-orange-950 text-orange-300 border-orange-900'}">${stock} 件${warn?' · 预警':''}</span></td><td class="p-3 text-center space-x-1 whitespace-nowrap"><button onclick="openQRViewModal('${p.id}')" class="text-[11px] bg-orange-950 px-2 py-1 rounded text-orange-300 font-bold hover:bg-orange-900 transition"><i class="fa-solid fa-qrcode mr-0.5"></i>二维码</button><button onclick="openEditModal('${p.id}')" class="text-[11px] bg-slate-700 px-2 py-1 rounded text-orange-300 font-bold hover:bg-slate-600 transition">编辑</button><button onclick="deleteProduct('${p.id}')" class="text-[11px] bg-red-950 px-2 py-1 rounded text-red-400 font-bold hover:bg-red-900 transition">删除</button></td></tr>`; }).join('');
            updateMockScannerDropdown();
            rebuildProductLookupMap();
        };
        // 保留高速扫码版 handleScannedProductId；手动模拟扫码也复用同一套 Map 与防抖逻辑。
        checkoutAndPrint = async function(){
            if (!requirePermission('sales_checkout', '当前账号无权结算。')) return; if(cart.length===0) return alert('购物车为空！');
            cart.forEach(item => { item.quantity = Math.max(1, parseInt(item.quantity || 1, 10)); });
            renderCartTable();
            for (const item of cart) { const p=products.find(x=>x.id===item.product.id); if(p && (p.stock ?? 0) < item.quantity && !confirm(`${p.name} 库存不足，仍要结算吗？`)) return; }
            const totalAmount=cart.reduce((sum,item)=>sum+(item.product.price*item.quantity*(item.discount||1)),0); const orderId='TX'+new Date().getTime().toString().substring(4); const orderDate=todayIso();
            const newOrder={id:orderId,total:totalAmount,date:orderDate,createdAt:new Date().toISOString(),operator:currentUser?currentUser.displayName:'未知用户',operatorId:currentUser?currentUser.id:'',items:cart.map(item=>({id:item.product.id,name:item.product.name,quantity:item.quantity,price:item.product.price,discount:item.discount||1,operator:currentUser?currentUser.displayName:'未知用户',subtotal:item.product.price*item.quantity*(item.discount||1)}))};
            newOrder.items.forEach(item => { const p=products.find(x=>x.id===item.id); if(p){ p.stock = Math.max(0, (p.stock ?? 0) - item.quantity); p.updatedAt=new Date().toISOString(); }});
            orders.push(newOrder); syncVersion++; saveAllLocal(); addAudit('结算订单', orderId, `￥${totalAmount.toFixed(2)} / ${newOrder.operator}`); openReceiptView(newOrder, '*** 结算交易物理凭证 ***'); clearCart(); renderProductTable(); updateReportDashboard(); await pushToCloud();
        };
        const oldRenderLedgerTable = renderLedgerTable;
        renderLedgerTable = function(){ oldRenderLedgerTable(); const tbody=document.getElementById('ledger-table-body'); if(tbody){ Array.from(tbody.querySelectorAll('tr')).forEach((tr,i)=>{ const order=[...orders].sort((a,b)=>new Date(b.date)-new Date(a.date))[i]; }); } };
        const oldUpdateReportDashboard = updateReportDashboard;
        updateReportDashboard = function(){ oldUpdateReportDashboard(); renderAuditTable(); };
        function csvEscape(v){ return '"' + String(v ?? '').replace(/"/g,'""') + '"'; }
        function downloadCsv(filename, rows){ const csv='\ufeff'+rows.map(r=>r.map(csvEscape).join(',')).join('\n'); const blob=new Blob([csv],{type:'text/csv;charset=utf-8;'}); const url=URL.createObjectURL(blob); const a=document.createElement('a'); a.href=url; a.download=filename; a.click(); setTimeout(()=>URL.revokeObjectURL(url),1000); }
        function exportOrdersCsv(){ if(!requirePermission('data_export','当前账号无权导出数据。')) return; const rows=[['订单号','日期','操作员','商品','数量','单价','折扣','小计','订单总额']]; orders.forEach(o=>(o.items||[]).forEach(i=>rows.push([o.id,o.createdAt||o.date,o.operator||i.operator||'',i.name,i.quantity,i.price||'',i.discount||1,i.subtotal,o.total]))); downloadCsv('orders.csv', rows); addAudit('导出数据','账单CSV',`${orders.length} 单`); }
        function exportProductsCsv(){ if(!requirePermission('data_export','当前账号无权导出数据。')) return; const rows=[['商品ID','名称','设计师','售价','库存','预警线','更新时间']].concat(products.map(p=>[p.id,p.name,p.designer,p.price,p.stock??0,p.lowStock??5,p.updatedAt||''])); downloadCsv('products.csv', rows); addAudit('导出数据','商品CSV',`${products.length} 件商品`); }
        function exportAuditCsv(){ if(!requirePermission('audit_view','当前账号无权查看审计日志。')) return; const rows=[['时间','用户','账号','动作','对象','说明']].concat(auditLogs.map(l=>[l.time,l.user,l.username,l.action,l.target,l.detail])); downloadCsv('audit_logs.csv', rows); addAudit('导出数据','审计日志CSV',`${auditLogs.length} 条`); }
        const oldResetSystemData = resetSystemData;
        resetSystemData = async function(){ if(!requirePermission('data_reset','当前账号无权初始化系统数据。')) return; addAudit('重置系统','全量数据','执行前记录'); await oldResetSystemData(); };
        const oldPushToCloud = pushToCloud;
        pushToCloud = async function(){
            if (!supabaseClient) return; syncVersion++; localStorage.setItem('sg_sync_version', String(syncVersion));
            try { const payload={sync_id:SY_ROOM_ID, products, orders, users, audit_logs:auditLogs, sync_version:syncVersion, updated_at:new Date().toISOString()}; const {error}=await supabaseClient.from('sync_store').upsert(payload); if(error) await supabaseClient.from('sync_store').upsert({sync_id:SY_ROOM_ID, products, orders, users, updated_at:new Date().toISOString()}); } catch(e){}
        };
        syncFromCloud = async function(){
            if (!supabaseClient) return;
            try { const {data}=await supabaseClient.from('sync_store').select('*').eq('sync_id',SY_ROOM_ID).single(); if(!data) return;
                const cloudVer=parseInt(data.sync_version || '0',10);
                const byId=(arr)=>Object.fromEntries((arr||[]).map(x=>[x.id,x]));
                if (cloudVer >= syncVersion) { products=data.products||products; orders=data.orders||orders; users=data.users||users; auditLogs=data.audit_logs||auditLogs; syncVersion=cloudVer; }
                else { products=Object.values({...byId(data.products),...byId(products)}); orders=Object.values({...byId(data.orders),...byId(orders)}); users=Object.values({...byId(data.users),...byId(users)}); auditLogs=Object.values({...byId(data.audit_logs),...byId(auditLogs)}).sort((a,b)=>new Date(a.time)-new Date(b.time)).slice(-1000); }
                saveAllLocal(); await migrateUsersSecurity(); renderProductTable(); renderCartTable(); updateReportDashboard(); renderUserTable(); renderAuditTable(); applyAuthUI();
            } catch(e) {}
        };

