// ===== PWA + 手机收银交互增强层 =====
(function(){
    let deferredInstallPrompt = null;
    function money(v){ return '￥' + Number(v || 0).toFixed(2); }
    function cartTotal(){ return (cart || []).reduce((sum,item)=>sum + item.product.price * item.quantity * (item.discount || 1), 0); }
    function ensureMobileShell(){
        if(!document.getElementById('mobile-checkout-bar')){
            const bar=document.createElement('div'); bar.id='mobile-checkout-bar'; bar.className='pwa-safe-bottom';
            bar.innerHTML=`<div><div class="text-[10px] text-slate-400 font-bold">移动收银合计</div><div id="mobile-cart-total" class="text-xl font-black text-orange-300">￥0.00</div><div id="mobile-cart-count" class="text-[10px] text-slate-500">0 件商品</div></div><button onclick="checkoutAndPrint()" class="bg-orange-500 hover:bg-orange-600 text-slate-950 font-black px-5 py-3 rounded-xl shadow-lg"><i class="fa-solid fa-bolt mr-1"></i>结算</button>`;
            document.body.appendChild(bar);
        }
        if(!document.getElementById('pwa-install-btn')){
            const btn=document.createElement('button'); btn.id='pwa-install-btn'; btn.className='mobile-install-btn'; btn.innerHTML='<i class="fa-solid fa-mobile-screen-button"></i>安装到桌面';
            btn.onclick=async()=>{ if(deferredInstallPrompt){ deferredInstallPrompt.prompt(); await deferredInstallPrompt.userChoice; deferredInstallPrompt=null; btn.style.display='none'; } else alert('请使用浏览器菜单里的“添加到主屏幕/安装应用”。'); };
            document.body.appendChild(btn);
        }
        if(!document.getElementById('network-status-badge')){
            const badge=document.createElement('div'); badge.id='network-status-badge'; document.body.appendChild(badge);
        }
        updateNetworkBadge();
    }
    function updateNetworkBadge(){
        const b=document.getElementById('network-status-badge'); if(!b) return;
        if(navigator.onLine){ b.innerHTML='<i class="fa-solid fa-cloud-arrow-up mr-1 text-emerald-400"></i>在线 · 自动同步'; b.style.borderColor='rgba(16,185,129,.35)'; }
        else { b.innerHTML='<i class="fa-solid fa-cloud mr-1 text-orange-300"></i>离线收银 · 本机暂存'; b.style.borderColor='rgba(249,115,22,.45)'; }
    }
    window.addEventListener('beforeinstallprompt', e=>{ e.preventDefault(); deferredInstallPrompt=e; const btn=document.getElementById('pwa-install-btn'); if(btn) btn.style.display='inline-flex'; });
    window.addEventListener('online', async()=>{ updateNetworkBadge(); try{ await pushToCloud(); if(typeof setScanStatus==='function') setScanStatus('网络已恢复，本机订单将自动同步。','ok'); }catch(e){} });
    window.addEventListener('offline', updateNetworkBadge);
    if('serviceWorker' in navigator){ window.addEventListener('load',()=>navigator.serviceWorker.register('./sw.js').catch(()=>{})); }

    const oldPlayBeep = window.playBeepSound;
    window.playBeepSound = function(){
        if(typeof oldPlayBeep === 'function') oldPlayBeep();
        try{ if(navigator.vibrate) navigator.vibrate([38,28,38]); }catch(e){}
    };

    function removeCartItem(idx){
        if(!cart[idx]) return;
        const name=cart[idx].product && cart[idx].product.name;
        cart.splice(idx,1); renderCartTable();
        if(typeof setScanStatus==='function') setScanStatus('已移除购物车商品：'+name,'warn');
    }
    window.mobileEditCartQty = function(idx){
        if(!cart[idx]) return;
        const val=prompt('请输入整数数量', cart[idx].quantity);
        if(val!==null) setCartQty(idx, val);
    };
    window.mobileRemoveCartItem = removeCartItem;

    function attachCartGestures(){
        document.querySelectorAll('.mobile-cart-card').forEach(card=>{
            let sx=0, dx=0, timer=null, idx=parseInt(card.dataset.idx,10);
            card.addEventListener('touchstart',e=>{ sx=e.touches[0].clientX; dx=0; card.classList.remove('swiping'); timer=setTimeout(()=>window.mobileEditCartQty(idx),650); },{passive:true});
            card.addEventListener('touchmove',e=>{ dx=e.touches[0].clientX-sx; if(Math.abs(dx)>12 && timer){clearTimeout(timer); timer=null;} if(dx < -12){ card.classList.add('swiping'); card.style.transform=`translateX(${Math.max(dx,-88)}px)`; } },{passive:true});
            card.addEventListener('touchend',()=>{ if(timer){clearTimeout(timer); timer=null;} card.style.transform=''; card.classList.remove('swiping'); if(dx < -72) removeCartItem(idx); });
        });
    }
    function updateMobileCheckoutBar(){
        ensureMobileShell();
        const count=(cart||[]).reduce((n,i)=>n+Math.max(1,parseInt(i.quantity||1,10)),0);
        const total=cartTotal();
        const mt=document.getElementById('mobile-cart-total'); if(mt) mt.textContent=money(total);
        const mc=document.getElementById('mobile-cart-count'); if(mc) mc.textContent=count+' 件商品';
    }

    const oldRenderCartTable = window.renderCartTable;
    window.renderCartTable = function(){
        const tbody=document.getElementById('cart-table-body');
        if(!tbody || !Array.isArray(cart)){ if(typeof oldRenderCartTable==='function') oldRenderCartTable(); updateMobileCheckoutBar(); return; }
        if(cart.length===0){
            tbody.innerHTML='<tr><td colspan="6" class="p-6 text-center text-slate-500">购物车为空。手机端可扫码、搜索或手动选择商品加入。</td></tr>';
            const totalEl=document.getElementById('cart-total-amount'); if(totalEl) totalEl.innerText='￥0.00';
            updateMobileCheckoutBar(); return;
        }
        let total=0;
        tbody.innerHTML=cart.map((item,idx)=>{
            item.quantity=Math.max(1,parseInt(item.quantity||1,10));
            const sub=item.product.price*item.quantity*(item.discount||1); total+=sub;
            return `<tr class="mobile-cart-card border-b border-slate-800 hover:bg-slate-800/40 transition" data-idx="${idx}" ondblclick="mobileEditCartQty(${idx})">
                <td class="p-3"><div class="font-bold text-slate-100">${item.product.name}</div><div class="text-[10px] text-slate-500 font-mono">${item.product.id} <span class="swipe-hint"> · 左滑删除 / 长按改数量</span></div></td>
                <td class="p-3 text-slate-300">${money(item.product.price)}</td>
                <td class="p-3"><select onchange="updateDiscount(${idx}, this.value)" class="bg-slate-950 border border-slate-600 rounded px-2 py-1 text-xs text-slate-100">${generateDiscountOptions(item.discount||1)}</select></td>
                <td class="p-3"><div class="flex items-center space-x-2"><button onclick="updateCartQty(${idx}, -1)" class="w-8 h-8 rounded-lg bg-slate-700 flex items-center justify-center hover:bg-slate-600 text-lg">−</button><input type="number" min="1" step="1" inputmode="numeric" pattern="[0-9]*" value="${item.quantity}" onchange="setCartQty(${idx}, this.value)" onblur="setCartQty(${idx}, this.value)" onkeydown="if(event.key==='Enter'){this.blur();}" class="w-20 bg-slate-950 border border-slate-600 rounded-lg px-2 py-1 text-center font-black text-slate-100 focus:outline-none focus:border-orange-500" title="可手动输入整数数量"><button onclick="updateCartQty(${idx}, 1)" class="w-8 h-8 rounded-lg bg-slate-700 flex items-center justify-center hover:bg-slate-600 text-lg">+</button></div></td>
                <td class="p-3 text-orange-300 font-black">${money(sub)}</td>
                <td class="p-3 text-center"><button onclick="mobileRemoveCartItem(${idx})" class="text-red-400 bg-red-950/60 border border-red-900 px-3 py-2 rounded-lg"><i class="fa-regular fa-trash-can"></i></button></td>
            </tr>`;
        }).join('');
        const totalEl=document.getElementById('cart-total-amount'); if(totalEl) totalEl.innerText=money(total);
        updateMobileCheckoutBar(); attachCartGestures();
    };

    const oldSetCartQty = window.setCartQty;
    window.setCartQty = function(index, value){
        const qty=parseInt(value,10);
        if(!Number.isInteger(qty) || qty<1){ alert('数量必须是大于 0 的整数。'); renderCartTable(); return; }
        cart[index].quantity=qty; renderCartTable(); saveAllLocal();
    };
    const oldClearCart=window.clearCart;
    window.clearCart=function(){ if(cart.length && !confirm('确定清空当前购物车吗？')) return; cart=[]; renderCartTable(); saveAllLocal(); };

    const oldHandleScan = window.handleScannedProductId;
    window.handleScannedProductId = function(prodId){
        const before=cartTotal();
        oldHandleScan(prodId);
        if(cartTotal()>before){
            try{ if(navigator.vibrate) navigator.vibrate(60); }catch(e){}
            const bar=document.getElementById('mobile-checkout-bar'); if(bar){ bar.animate([{transform:'translateY(0)'},{transform:'translateY(-5px)'},{transform:'translateY(0)'}],{duration:220}); }
        }
    };

    document.addEventListener('DOMContentLoaded',()=>{ ensureMobileShell(); setTimeout(()=>{ try{ renderCartTable(); }catch(e){} },200); });
})();

/* ===== END assets/js/patches/70-pwa-mobile-pos.js ===== */


/* ===== BEGIN assets/js/patches/71-user-stability-fix.js ===== */
// ===== 用户稳定性修复补丁 v3 =====
(function(){
    const ADMIN_ROLE = 'admin';

    function getLiveCurrentUser(){
        if(!currentUser) return null;
        const live = (users || []).find(u => u.id === currentUser.id || u.username === currentUser.username);
        if(!live || live.status !== 'active') return null;
        return live;
    }

    function syncCurrentUserFromLive(){
        const live = getLiveCurrentUser();
        if(!live){
            if(currentUser){
                try { addAudit('会话失效', currentUser.username || currentUser.id || '未知账号', '账号已被停用或删除，已自动退出'); } catch(e){}
            }
            currentUser = null;
            localStorage.removeItem('sg_current_user');
            return null;
        }
        currentUser = { id: live.id, username: live.username, displayName: live.displayName, role: live.role };
        localStorage.setItem('sg_current_user', JSON.stringify(currentUser));
        return live;
    }

    function getUserPermissions(user){
        if(!user || user.status !== 'active') return [];
        if(Array.isArray(user.permissions) && user.permissions.length) return user.permissions;
        return ROLE_PERMISSIONS[user.role] || [];
    }

    function hasActiveAdmin(list){
        return (list || []).some(u => u && u.status === 'active' && u.role === ADMIN_ROLE);
    }

    function normalizeUserRecord(u){
        if(!u) return u;
        if(!u.id) u.id = 'U-' + Date.now() + '-' + Math.random().toString(36).slice(2,6);
        if(!u.status) u.status = 'active';
        if(!u.role) u.role = 'cashier';
        u.permissions = ROLE_PERMISSIONS[u.role] || [];
        return u;
    }

    const oldHasPermissionV3 = window.hasPermission || hasPermission;
    window.hasPermission = hasPermission = function(permission){
        const live = syncCurrentUserFromLive();
        if(!live) return false;
        return getUserPermissions(live).includes(permission);
    };

    const oldApplyAuthUIV3 = window.applyAuthUI || applyAuthUI;
    window.applyAuthUI = applyAuthUI = function(){
        syncCurrentUserFromLive();
        const loggedIn = !!currentUser;
        const loginModal = document.getElementById('login-modal');
        const logoutBtn = document.getElementById('btn-logout');
        const badge = document.getElementById('current-user-badge');
        const name = document.getElementById('current-user-name');
        if(loginModal) loginModal.classList.toggle('hidden', loggedIn);
        if(logoutBtn) logoutBtn.classList.toggle('hidden', !loggedIn);
        if(badge) badge.classList.toggle('hidden', !loggedIn);
        if(loggedIn && name) name.innerText = `${currentUser.displayName} · ${ROLE_LABELS[currentUser.role] || currentUser.role}`;

        document.querySelectorAll('[data-permission]').forEach(el => {
            el.classList.toggle('hidden', !hasPermission(el.dataset.permission));
        });

        const availableTabs = ['product-tab', 'sales-tab', 'report-tab', 'user-tab'].filter(tab => {
            if (tab === 'product-tab') return hasPermission('product_manage');
            if (tab === 'sales-tab') return hasPermission('sales_checkout');
            if (tab === 'report-tab') return hasPermission('report_view');
            if (tab === 'user-tab') return hasPermission('user_manage');
            return false;
        });
        if (loggedIn) {
            const active = document.querySelector('.tab-content:not(.hidden)');
            if (!active || !availableTabs.includes(active.id)) switchTab(availableTabs[0] || 'sales-tab');
        }
    };

    const oldSaveUserAccountV3 = window.saveUserAccount || saveUserAccount;
    window.saveUserAccount = saveUserAccount = async function(e){
        e.preventDefault();
        if (!requirePermission('user_manage')) return;
        const editId = document.getElementById('u-edit-id').value;
        const username = document.getElementById('u-username').value.trim();
        const displayName = document.getElementById('u-display-name').value.trim();
        const password = document.getElementById('u-password').value;
        const role = document.getElementById('u-role').value;
        const status = document.getElementById('u-status').value;
        if (!username || !displayName) return alert('请填写登录账号和显示名称。');
        if (!editId && password.length < 6) return alert('新用户密码至少 6 位。');
        if (!editId && users.some(u => String(u.username).toLowerCase() === username.toLowerCase())) return alert('该登录账号已存在。');

        const nextUsers = users.map(u => ({...u}));
        if (editId) {
            const idx = nextUsers.findIndex(x => x.id === editId);
            if (idx === -1) return;
            nextUsers[idx].displayName = displayName;
            nextUsers[idx].role = role;
            nextUsers[idx].status = status;
            nextUsers[idx].permissions = ROLE_PERMISSIONS[role] || [];
            nextUsers[idx].updatedAt = new Date().toISOString();
            if (!hasActiveAdmin(nextUsers)) return alert('系统必须至少保留一个“启用”的管理员账号。');
            if (password) {
                if(password.length < 6) return alert('新密码至少 6 位。');
                const hp = await hashPassword(password);
                nextUsers[idx].passwordSalt = hp.salt;
                nextUsers[idx].passwordHash = hp.hash;
                delete nextUsers[idx].password;
            }
            users = nextUsers.map(normalizeUserRecord);
            addAudit('编辑用户', username, `角色：${ROLE_LABELS[role] || role}，状态：${status}`);
        } else {
            const hp = await hashPassword(password);
            nextUsers.push(normalizeUserRecord({ id:'U-'+Date.now(), username, passwordSalt:hp.salt, passwordHash:hp.hash, displayName, role, permissions:ROLE_PERMISSIONS[role]||[], status, createdAt:new Date().toISOString(), updatedAt:new Date().toISOString(), lastLogin:'' }));
            if (!hasActiveAdmin(nextUsers)) return alert('系统必须至少保留一个“启用”的管理员账号。');
            users = nextUsers.map(normalizeUserRecord);
            addAudit('新增用户', username, `角色：${ROLE_LABELS[role] || role}`);
        }
        syncCurrentUserFromLive();
        syncVersion++;
        saveAllLocal();
        resetUserForm();
        renderUserTable();
        applyAuthUI();
        await pushToCloud();
    };

    const oldDeleteUserAccountV3 = window.deleteUserAccount || deleteUserAccount;
    window.deleteUserAccount = deleteUserAccount = async function(id){
        if (!requirePermission('user_manage')) return;
        const u = users.find(x => x.id === id);
        if (!u) return;
        if (currentUser && currentUser.id === id) return alert('不能删除当前登录账号。');
        const nextUsers = users.filter(x => x.id !== id);
        if (!nextUsers.length) return alert('至少保留一个系统账号。');
        if (!hasActiveAdmin(nextUsers)) return alert('不能删除最后一个启用的管理员账号。');
        if (!confirm('确定删除此用户吗？')) return;
        users = nextUsers.map(normalizeUserRecord);
        syncVersion++;
        saveAllLocal();
        addAudit('删除用户', u.username, '');
        renderUserTable();
        applyAuthUI();
        await pushToCloud();
    };

    const oldRenderUserTableV3 = window.renderUserTable || renderUserTable;
    window.renderUserTable = renderUserTable = function(){
        users = (users || []).map(normalizeUserRecord);
        const tbody = document.getElementById('user-table-body');
        if (!tbody) return;
        tbody.innerHTML = users.map(u => {
            const isCurrent = currentUser && currentUser.id === u.id;
            const lastAdmin = u.status === 'active' && u.role === ADMIN_ROLE && (users || []).filter(x => x.status === 'active' && x.role === ADMIN_ROLE).length === 1;
            return `<tr class="border-b border-slate-800 hover:bg-slate-800/40 transition">
                <td class="p-3 font-mono text-orange-300 font-bold">${escapeHtml(u.username)}${isCurrent ? '<span class="ml-2 text-[10px] bg-orange-500 text-slate-950 px-1.5 py-0.5 rounded">当前</span>' : ''}${lastAdmin ? '<span class="ml-2 text-[10px] bg-slate-700 text-slate-200 px-1.5 py-0.5 rounded">唯一管理员</span>' : ''}</td>
                <td class="p-3 text-slate-200">${escapeHtml(u.displayName)}</td>
                <td class="p-3"><span class="bg-slate-900 border border-slate-700 px-2 py-0.5 rounded text-slate-300">${escapeHtml(ROLE_LABELS[u.role] || u.role)}</span></td>
                <td class="p-3 ${u.status === 'active' ? 'text-orange-300' : 'text-red-400'}">${u.status === 'active' ? '启用' : '停用'}</td>
                <td class="p-3 text-slate-400">${escapeHtml(u.lastLogin || '暂无')}</td>
                <td class="p-3 text-center space-x-1 whitespace-nowrap">
                    <button onclick="editUserAccount('${u.id}')" class="text-[11px] bg-slate-700 px-2 py-1 rounded text-orange-300 font-bold hover:bg-slate-600 transition">编辑</button>
                    <button onclick="deleteUserAccount('${u.id}')" class="text-[11px] bg-red-950 px-2 py-1 rounded text-red-400 font-bold hover:bg-red-900 transition ${isCurrent || lastAdmin ? 'opacity-40 cursor-not-allowed' : ''}" ${isCurrent || lastAdmin ? 'disabled' : ''}>删除</button>
                </td>
            </tr>`;
        }).join('');
        try { renderAuditTable(); } catch(e){}
    };

    const oldSyncFromCloudV3 = window.syncFromCloud || syncFromCloud;
    window.syncFromCloud = syncFromCloud = async function(){
        await oldSyncFromCloudV3();
        users = (users || []).map(normalizeUserRecord);
        if (!hasActiveAdmin(users)) {
            users.push(normalizeUserRecord({ id:'U-ADMIN-RECOVERY', username:'admin', password:'admin123', displayName:'系统管理员', role:'admin', status:'active', createdAt:new Date().toISOString(), lastLogin:'' }));
            try { await migrateUsersSecurity(); } catch(e){}
        }
        syncCurrentUserFromLive();
        saveAllLocal();
        renderUserTable();
        applyAuthUI();
    };

    document.addEventListener('DOMContentLoaded', () => {
        setTimeout(() => {
            users = (users || []).map(normalizeUserRecord);
            if (!hasActiveAdmin(users)) {
                users.push(normalizeUserRecord({ id:'U-ADMIN-RECOVERY', username:'admin', password:'admin123', displayName:'系统管理员', role:'admin', status:'active', createdAt:new Date().toISOString(), lastLogin:'' }));
                try { migrateUsersSecurity(); } catch(e){}
            }
            syncCurrentUserFromLive();
            saveAllLocal();
            try { renderUserTable(); applyAuthUI(); } catch(e){}
        }, 300);
    });
})();

/* ===== END assets/js/patches/71-user-stability-fix.js ===== */


/* ===== BEGIN assets/js/patches/78-auto-sync-v9.js ===== */
// ===== 自动云同步层 v9：基于已验证的 v8 通道，恢复商品/库存/订单/用户/日志自动同步 =====
(function(){
    const AUTO_SYNC_VERSION = 'v9-auto-all-data-sync';
    const META_PRODUCT_ID = '__SG_CLOUD_META__';
    const META_ORDER_ID = '__SG_CLOUD_STATE__';
    const TOMBSTONE_KEY = 'sg_deleted_records';
    const AUTO_INTERVAL_MS = 45000;
    const IDLE_UPLOAD_DELAY_MS = 1800;
    const nowIso = () => new Date().toISOString();
    const arr = v => Array.isArray(v) ? v : [];
    const parseIntSafe = (v, fb = 0) => { const n = parseInt(v, 10); return Number.isFinite(n) ? n : fb; };
    const parseNumSafe = (v, fb = 0) => { const n = Number(v); return Number.isFinite(n) ? n : fb; };
    const dateNum = v => { const n = Date.parse(v || ''); return Number.isFinite(n) ? n : 0; };
    const timeOf = x => Math.max(dateNum(x && x.updatedAt), dateNum(x && x.deletedAt), dateNum(x && x.modifiedAt), dateNum(x && x.createdAt), dateNum(x && x.time), dateNum(x && x.lastLogin));
    function getClient(){
        try { if (window.supabaseClient) return window.supabaseClient; } catch(e) {}
        try { if (typeof supabaseClient !== 'undefined' && supabaseClient) { window.supabaseClient = supabaseClient; return supabaseClient; } } catch(e) {}
        return null;
    }
    function isMetaProduct(p){ return p && (p.id === META_PRODUCT_ID || p.__syncMeta === true || (p.hidden === true && /同步元数据/.test(String(p.name || '')))); }
    function isMetaOrder(o){ return o && (o.id === META_ORDER_ID || o.__syncMeta === true); }
    function stripProducts(list){ return arr(list).filter(p => p && !isMetaProduct(p)); }
    function stripOrders(list){ return arr(list).filter(o => o && !isMetaOrder(o)); }
    function loadTombstones(){ try { const x = JSON.parse(localStorage.getItem(TOMBSTONE_KEY) || '{}'); return x && typeof x === 'object' ? x : {}; } catch(e) { return {}; } }
    function saveTombstones(t){ try { localStorage.setItem(TOMBSTONE_KEY, JSON.stringify(t || {})); } catch(e) {} }
    function addTombstone(type, id){ if (!id) return; const t = loadTombstones(); t[type] = t[type] || {}; t[type][id] = nowIso(); saveTombstones(t); }
    // 暴露给管理员清除销售记录功能：逐条写入删除墓碑，避免云端旧订单被再次合并回来。
    window.__sgAddTombstone = addTombstone;
    window.__sgLoadTombstones = loadTombstones;
    function pruneTombstones(t){
        const cutoff = Date.now() - 1000 * 60 * 60 * 24 * 30;
        for (const group of Object.values(t || {})) {
            for (const [id, ts] of Object.entries(group || {})) if (dateNum(ts) && dateNum(ts) < cutoff) delete group[id];
        }
        return t || {};
    }
    function normalizeProduct(p, fallbackTime){
        if (!p || !p.id || isMetaProduct(p)) return null;
        const o = {...p};
        o.price = parseNumSafe(o.price, 0);
        o.stock = Math.max(0, parseIntSafe(o.stock, 0));
        o.lowStock = Math.max(0, parseIntSafe(o.lowStock, 5));
        o.updatedAt = o.updatedAt || o.modifiedAt || o.createdAt || fallbackTime || '1970-01-01T00:00:00.000Z';
        return o;
    }
    function normalizeOrder(o, fallbackTime){
        if (!o || !o.id || isMetaOrder(o)) return null;
        const x = {...o};
        x.createdAt = x.createdAt || (x.date ? x.date + 'T00:00:00.000Z' : fallbackTime || '1970-01-01T00:00:00.000Z');
        x.updatedAt = x.updatedAt || x.createdAt;
        return x;
    }
    function normalizeUser(u, fallbackTime){
        if (!u || !u.id) return null;
        let x = {...u};
        try { if (typeof normalizeUserRecord === 'function') x = normalizeUserRecord(x); } catch(e) {}
        x.status = x.status || 'active';
        x.role = x.role || 'cashier';
        try { x.permissions = Array.isArray(x.permissions) && x.permissions.length ? x.permissions : ((ROLE_PERMISSIONS && ROLE_PERMISSIONS[x.role]) || []); } catch(e) {}
        x.updatedAt = x.updatedAt || x.modifiedAt || x.createdAt || x.lastLogin || fallbackTime || '1970-01-01T00:00:00.000Z';
        return x;
    }
    function normalizeAudit(l, fallbackTime){
        if (!l) return null;
        const x = {...l};
        x.id = x.id || ('LOG-' + (x.time || x.createdAt || Date.now()) + '-' + Math.random().toString(36).slice(2, 8));
        x.time = x.time || x.createdAt || fallbackTime || '1970-01-01T00:00:00.000Z';
        x.updatedAt = x.updatedAt || x.time;
        return x;
    }
    function normalizeLocalState(){
        products = stripProducts(products).map(p => normalizeProduct(p)).filter(Boolean);
        orders = stripOrders(orders).map(o => normalizeOrder(o)).filter(Boolean);
        users = arr(users).map(u => normalizeUser(u)).filter(Boolean);
        auditLogs = arr(auditLogs).map(l => normalizeAudit(l)).filter(Boolean).sort((a,b) => timeOf(a) - timeOf(b)).slice(-1000);
    }
    function mergeRecords(localList, cloudList, normalizer, deletedMap){
        const m = new Map();
        for (const list of [arr(cloudList), arr(localList)]) {
            for (const raw of list) {
                const item = normalizer(raw);
                if (!item || !item.id) continue;
                const deletedAt = deletedMap && deletedMap[item.id] ? dateNum(deletedMap[item.id]) : 0;
                if (deletedAt && deletedAt >= timeOf(item)) continue;
                const old = m.get(item.id);
                if (!old || timeOf(item) >= timeOf(old)) m.set(item.id, item);
            }
        }
        return Array.from(m.values());
    }
    function extractCloudState(data){
        if (!data) return {products:[], orders:[], users:[], audit_logs:[], deleted:{}, sync_version:0};
        const rawProducts = arr(data.products), rawOrders = arr(data.orders);
        const productMeta = rawProducts.find(isMetaProduct);
        const orderMeta = rawOrders.find(isMetaOrder);
        const st0 = data.app_state || (productMeta && productMeta.meta) || (orderMeta && orderMeta.meta) || {};
        const st = st0.state || st0;
        return {
            products: stripProducts(arr(st.products).length ? st.products : rawProducts).map(p => normalizeProduct(p)).filter(Boolean),
            orders: stripOrders(arr(st.orders).length ? st.orders : rawOrders).map(o => normalizeOrder(o)).filter(Boolean),
            users: (arr(data.users).length ? data.users : (arr(st.users).length ? st.users : arr(st0.users))).map(u => normalizeUser(u)).filter(Boolean),
            audit_logs: (arr(data.audit_logs).length ? data.audit_logs : (arr(st.audit_logs).length ? st.audit_logs : arr(st0.audit_logs))).map(l => normalizeAudit(l)).filter(Boolean),
            deleted: st.deleted || st0.deleted || {},
            sync_version: parseIntSafe(data.sync_version || st.sync_version || st0.sync_version, 0)
        };
    }
    async function readCloudState(){
        const client = getClient();
        if (!client) throw new Error('未连接 Supabase：请检查配置或网络。');
        const {data, error} = await client.from('sync_store').select('*').eq('sync_id', SY_ROOM_ID).maybeSingle();
        if (error) throw error;
        return extractCloudState(data);
    }
    function packProducts(state){
        return arr(state.products).map(p => normalizeProduct(p, nowIso())).filter(Boolean).concat([{id:META_PRODUCT_ID,__syncMeta:true,hidden:true,name:'系统同步元数据，请勿删除',price:0,stock:0,lowStock:0,updatedAt:nowIso(),meta:state}]);
    }
    function packOrders(state){
        return arr(state.orders).map(o => normalizeOrder(o, nowIso())).filter(Boolean).concat([{id:META_ORDER_ID,__syncMeta:true,hidden:true,total:0,date:nowIso().slice(0,10),createdAt:nowIso(),updatedAt:nowIso(),items:[],meta:state}]);
    }
    async function writeCloudState(state){
        const client = getClient();
        if (!client) throw new Error('未连接 Supabase：请检查配置或网络。');
        const next = {
            schema_version: 9,
            sync_version: parseIntSafe(state.sync_version, 0) + 1,
            updated_at: nowIso(),
            products: arr(state.products).map(p => normalizeProduct(p, nowIso())).filter(Boolean),
            orders: arr(state.orders).map(o => normalizeOrder(o, nowIso())).filter(Boolean),
            users: arr(state.users).map(u => normalizeUser(u, nowIso())).filter(Boolean),
            audit_logs: arr(state.audit_logs).map(l => normalizeAudit(l, nowIso())).filter(Boolean).sort((a,b) => timeOf(a) - timeOf(b)).slice(-1000),
            deleted: pruneTombstones(state.deleted || {})
        };
        const fullPayload = {sync_id: SY_ROOM_ID, products: next.products, orders: next.orders, users: next.users, audit_logs: next.audit_logs, sync_version: next.sync_version, app_state: next, updated_at: next.updated_at};
        const packedPayload = {sync_id: SY_ROOM_ID, products: packProducts(next), orders: packOrders(next), updated_at: next.updated_at};
        try {
            const r = await client.from('sync_store').upsert(fullPayload, {onConflict:'sync_id'});
            if (r && !r.error) return next;
        } catch(e) {}
        const r2 = await client.from('sync_store').upsert(packedPayload, {onConflict:'sync_id'});
        if (r2 && r2.error) throw r2.error;
        return next;
    }
    function saveRender(){
        normalizeLocalState();
        try {
            localStorage.setItem('sg_products', JSON.stringify(products));
            localStorage.setItem('sg_orders', JSON.stringify(orders));
            localStorage.setItem('sg_users', JSON.stringify(users));
            localStorage.setItem('sg_audit_logs', JSON.stringify(auditLogs));
            localStorage.setItem('sg_sync_version', String(syncVersion || 0));
        } catch(e) {}
        try { if (typeof migrateUsersSecurity === 'function') migrateUsersSecurity(); } catch(e) {}
        try { if (typeof syncCurrentUserFromLive === 'function') syncCurrentUserFromLive(); } catch(e) {}
        try { renderProductTable(); renderCartTable(); updateReportDashboard(); renderUserTable(); renderAuditTable(); applyAuthUI(); updateAutoSyncPanel(); } catch(e) {}
    }
    let syncLock = null;
    let lastAutoSyncAt = 0;
    let pendingTimer = null;
    let lastSyncError = '';
    async function syncAllNow(reason){
        if (!navigator.onLine) { updateAutoSyncPanel('offline'); return false; }
        if (syncLock) return syncLock;
        syncLock = (async () => {
            const client = getClient();
            if (!client) { lastSyncError = '未连接 Supabase'; updateAutoSyncPanel('error'); return false; }
            try {
                normalizeLocalState();
                const cloud = await readCloudState();
                const localDeleted = loadTombstones();
                const deleted = pruneTombstones({
                    products: {...(cloud.deleted && cloud.deleted.products || {}), ...(localDeleted.products || {})},
                    orders: {...(cloud.deleted && cloud.deleted.orders || {}), ...(localDeleted.orders || {})},
                    users: {...(cloud.deleted && cloud.deleted.users || {}), ...(localDeleted.users || {})},
                    audit_logs: {...(cloud.deleted && cloud.deleted.audit_logs || {}), ...(localDeleted.audit_logs || {})}
                });
                products = mergeRecords(products, cloud.products, normalizeProduct, deleted.products || {});
                orders = mergeRecords(orders, cloud.orders, normalizeOrder, deleted.orders || {});
                users = mergeRecords(users, cloud.users, normalizeUser, deleted.users || {});
                auditLogs = mergeRecords(auditLogs, cloud.audit_logs, normalizeAudit, deleted.audit_logs || {}).sort((a,b) => timeOf(a) - timeOf(b)).slice(-1000);
                try {
                    if (typeof hasActiveAdmin === 'function' && !hasActiveAdmin(users)) {
                        users.push(normalizeUser({id:'U-ADMIN-RECOVERY',username:'admin',password:'admin123',displayName:'系统管理员',role:'admin',status:'active',createdAt:nowIso(),updatedAt:nowIso(),lastLogin:''}, nowIso()));
                    }
                    if (typeof migrateUsersSecurity === 'function') await migrateUsersSecurity();
                } catch(e) {}
                const nextVersion = Math.max(parseIntSafe(syncVersion, 0), parseIntSafe(cloud.sync_version, 0));
                const written = await writeCloudState({products, orders, users, audit_logs: auditLogs, deleted, sync_version: nextVersion});
                syncVersion = parseIntSafe(written.sync_version, nextVersion);
                saveTombstones(written.deleted || deleted);
                saveRender();
                lastAutoSyncAt = Date.now();
                lastSyncError = '';
                updateAutoSyncPanel('ok', reason);
                return true;
            } catch(e) {
                lastSyncError = e && e.message ? e.message : String(e);
                console.warn('自动云同步失败：', e);
                updateAutoSyncPanel('error');
                return false;
            } finally {
                syncLock = null;
            }
        })();
        return syncLock;
    }
    function scheduleAutoSync(reason, delay = IDLE_UPLOAD_DELAY_MS){
        clearTimeout(pendingTimer);
        pendingTimer = setTimeout(() => { syncAllNow(reason); }, delay);
    }
    window.__sgScheduleAutoSync = scheduleAutoSync;

    // 让原来所有 await pushToCloud() 的位置自动变成全量自动同步。
    window.pushToCloud = pushToCloud = async function(){ return syncAllNow('local-change'); };
    window.syncFromCloud = syncFromCloud = async function(){ return syncAllNow('pull-merge'); };

    // patch 本地保存：不阻塞界面，保存后自动延迟同步。
    const oldSaveAllLocal = window.saveAllLocal || (typeof saveAllLocal !== 'undefined' ? saveAllLocal : null);
    if (oldSaveAllLocal) {
        window.saveAllLocal = saveAllLocal = function(){
            const r = oldSaveAllLocal.apply(this, arguments);
            scheduleAutoSync('save-local');
            return r;
        };
    }

    // 删除商品必须记录墓碑，否则“自动合并”会把云端旧商品重新合回来。
    const oldDeleteProduct = window.deleteProduct || (typeof deleteProduct !== 'undefined' ? deleteProduct : null);
    if (oldDeleteProduct) {
        window.deleteProduct = deleteProduct = async function(id){
            const before = arr(products).some(p => p && p.id === id);
            const result = await oldDeleteProduct.apply(this, arguments);
            const after = arr(products).some(p => p && p.id === id);
            if (before && !after) { addTombstone('products', id); scheduleAutoSync('delete-product', 200); }
            return result;
        };
    }
    const oldDeleteUser = window.deleteUserAccount || (typeof deleteUserAccount !== 'undefined' ? deleteUserAccount : null);
    if (oldDeleteUser) {
        window.deleteUserAccount = deleteUserAccount = async function(id){
            const before = arr(users).some(u => u && u.id === id);
            const result = await oldDeleteUser.apply(this, arguments);
            const after = arr(users).some(u => u && u.id === id);
            if (before && !after) { addTombstone('users', id); scheduleAutoSync('delete-user', 200); }
            return result;
        };
    }
    const oldDeleteAudit = window.deleteAuditLog || (typeof deleteAuditLog !== 'undefined' ? deleteAuditLog : null);
    if (oldDeleteAudit) {
        window.deleteAuditLog = deleteAuditLog = async function(id){
            const before = arr(auditLogs).some(l => l && l.id === id);
            const result = await oldDeleteAudit.apply(this, arguments);
            const after = arr(auditLogs).some(l => l && l.id === id);
            if (before && !after) { addTombstone('audit_logs', id); scheduleAutoSync('delete-audit', 200); }
            return result;
        };
    }

    // 兼容旧按钮：不再弹确认，直接触发一次自动同步。
    window.manualUploadBusinessToCloud = async function(){ const ok = await syncAllNow('manual-upload-button'); alert(ok ? '已完成自动同步。' : '自动同步失败：' + (lastSyncError || '请检查网络/Supabase 配置。')); };
    window.manualDownloadBusinessFromCloud = async function(){ const ok = await syncAllNow('manual-download-button'); alert(ok ? '已从云端合并并完成自动同步。' : '自动同步失败：' + (lastSyncError || '请检查网络/Supabase 配置。')); };

    function installAutoSyncPanel(){
        let box = document.getElementById('manual-sync-box') || document.getElementById('auto-sync-box');
        const host = document.querySelector('main');
        if (!box && host) {
            box = document.createElement('section');
            box.id = 'auto-sync-box';
            box.className = 'max-w-7xl mx-auto px-4 pt-4';
            host.parentNode.insertBefore(box, host);
        }
        if (box) {
            box.id = 'auto-sync-box';
            box.removeAttribute('data-permission');
            box.innerHTML = '<div class="bg-slate-800 border border-orange-500/30 rounded-xl p-3 shadow-xl flex flex-col sm:flex-row items-start sm:items-center justify-between gap-3"><div><div class="text-sm font-black text-orange-300"><i class="fa-solid fa-cloud-arrow-up mr-2"></i>自动云同步</div><div id="auto-sync-info" class="text-[11px] text-slate-400 mt-1">正在准备自动同步...</div><div class="text-[10px] text-slate-500 mt-1">商品库存、订单、用户、审计日志会自动合并同步；购物车和当前登录会话仅保存在本机。</div></div><div class="text-[11px] text-slate-500 font-bold px-3 py-2 rounded-lg border border-slate-700 bg-slate-900/60"><i class="fa-solid fa-circle-nodes mr-1 text-orange-300"></i>后台自动同步</div></div>';
        }
        updateAutoSyncPanel();
    }
    window.updateManualSyncPanel = function(){ updateAutoSyncPanel(); };
    window.updateAutoSyncPanel = function(status, reason){
        const info = document.getElementById('auto-sync-info') || document.getElementById('manual-sync-info');
        if (!info) return;
        const online = navigator.onLine;
        const last = lastAutoSyncAt ? new Date(lastAutoSyncAt).toLocaleTimeString() : '尚未完成';
        let msg = (online ? '在线' : '离线') + ' · 自动同步开启 · 商品 ' + (products ? products.length : 0) + ' / 订单 ' + (orders ? orders.length : 0) + ' / 用户 ' + (users ? users.length : 0) + ' / 日志 ' + (auditLogs ? auditLogs.length : 0) + ' · 上次同步：' + last;
        if (status === 'error') msg += ' · 错误：' + (lastSyncError || '同步失败');
        if (status === 'offline') msg += ' · 离线，本机暂存，联网后自动同步';
        if (reason) msg += ' · ' + reason;
        info.textContent = msg;
        const b = document.getElementById('network-status-badge');
        if (b) {
            b.innerHTML = online ? '<i class="fa-solid fa-cloud-arrow-up mr-1 text-orange-300"></i>在线 · 自动同步' : '<i class="fa-solid fa-cloud mr-1 text-orange-300"></i>离线收银 · 联网后同步';
            b.style.borderColor = 'rgba(249,115,22,.45)';
        }
    };
    window.updateNetworkBadge = function(){ updateAutoSyncPanel(navigator.onLine ? 'ok' : 'offline'); };

    document.addEventListener('DOMContentLoaded', () => {
        setTimeout(() => { installAutoSyncPanel(); syncAllNow('startup'); }, 900);
        setInterval(() => { if (navigator.onLine) syncAllNow('interval'); }, AUTO_INTERVAL_MS);
    });
    window.addEventListener('online', () => syncAllNow('online'));
    window.addEventListener('focus', () => { if (Date.now() - lastAutoSyncAt > 10000) syncAllNow('focus'); });
    window.addEventListener('beforeunload', () => { try { if (navigator.onLine) syncAllNow('beforeunload'); } catch(e) {} });

    window.__sgAutoSyncCheck = async function(){
        const clientOK = !!getClient();
        const localSample = arr(products).map(p => normalizeProduct(p)).filter(Boolean)[0] || null;
        let cloudSummary = null;
        try {
            if (clientOK) {
                const cloud = await readCloudState();
                const cp = arr(cloud.products)[0] || null;
                cloudSummary = {products: cloud.products.length, orders: cloud.orders.length, users: cloud.users.length, auditLogs: cloud.audit_logs.length, syncVersion: cloud.sync_version, sampleProduct: cp ? {id:cp.id, stock:cp.stock, lowStock:cp.lowStock, updatedAt:cp.updatedAt} : null, tombstones: cloud.deleted || {}};
            }
        } catch(e) { cloudSummary = {error: e && e.message ? e.message : String(e)}; }
        return {version:AUTO_SYNC_VERSION, supabaseClientAvailable:clientOK, mode:'all_data_auto_sync', autoSync:['products including stock/lowStock','orders','users/accounts','auditLogs','delete tombstones'], local:{products:products&&products.length,orders:orders&&orders.length,users:users&&users.length,auditLogs:auditLogs&&auditLogs.length,syncVersion:syncVersion||0,sampleProduct:localSample?{id:localSample.id,stock:localSample.stock,lowStock:localSample.lowStock,updatedAt:localSample.updatedAt}:null}, cloud:cloudSummary, lastAutoSyncAt:lastAutoSyncAt?new Date(lastAutoSyncAt).toISOString():null, lastSyncError};
    };
    window.__sgBusinessSyncCheck = window.__sgAutoSyncCheck;
    console.info('第二引力销售系统自动同步层已加载：', AUTO_SYNC_VERSION);
})();

/* ===== END assets/js/patches/78-auto-sync-v9.js ===== */


