// ===== UI 清理层 v10：移除手动业务云同步入口，只保留自动同步状态 =====
(function(){
    function removeManualBusinessSyncControls(){
        document.querySelectorAll('button[onclick="manualUploadBusinessToCloud()"], button[onclick="manualDownloadBusinessFromCloud()"], button[onclick="syncFromCloud()"]')
            .forEach(btn => {
                const text=(btn.textContent||'').trim();
                if (/上传业务数据|下载\/合并业务数据|立即同步/.test(text)) btn.remove();
            });
        const box=document.getElementById('manual-sync-box');
        if(box){ const auto=document.getElementById('auto-sync-box'); if(auto) box.remove(); else box.id='auto-sync-box'; }
        const title=document.querySelector('#auto-sync-box .text-sm, #manual-sync-box .text-sm');
        if(title && /手动业务云同步/.test(title.textContent||'')) title.innerHTML='<i class="fa-solid fa-cloud-arrow-up mr-2"></i>自动云同步';
        const info=document.getElementById('manual-sync-info');
        if(info) info.id='auto-sync-info';
        document.querySelectorAll('#auto-sync-box .text-\[10px\], #manual-sync-box .text-\[10px\]').forEach(el=>{
            if(/手动|按钮|不会自动|上传|下载/.test(el.textContent||'')) el.textContent='商品库存、订单、用户、审计日志会自动合并同步；购物车和当前登录会话仅保存在本机。';
        });
    }
    document.addEventListener('DOMContentLoaded',()=>setTimeout(removeManualBusinessSyncControls,1200));
    window.addEventListener('focus',()=>setTimeout(removeManualBusinessSyncControls,200));
    window.__sgAutoSyncUIMode=function(){return {mode:'auto_sync_only', manualBusinessSyncUI:false};};
})();

/* ===== END assets/js/patches/79-ui-cleanup-v10.js ===== */


/* ===== BEGIN assets/js/patches/80-scanner-keyboard-v11.js ===== */
// ===== 扫码枪录入增强层 v11：实体扫码枪/键盘楔入快速录入 =====
(function(){
    const SCANNER_MIN_LEN = 3;
    const SCANNER_MAX_INTERVAL = 90;   // 扫码枪字符间隔通常很短；人工输入一般更慢
    const SCANNER_RESET_DELAY = 220;
    let gunBuffer = '';
    let gunLastTime = 0;
    let gunResetTimer = null;

    function isSalesTabVisible(){
        const tab = document.getElementById('sales-tab');
        return !!tab && !tab.classList.contains('hidden');
    }

    function canUseCashier(){
        try { return typeof hasPermission === 'function' ? hasPermission('sales_checkout') : true; }
        catch(e){ return true; }
    }

    function setGunStatus(text, tone){
        const el = document.getElementById('scanner-gun-status');
        if(el){
            el.className = 'text-[10px] rounded-lg px-2 py-1 border ' + (
                tone === 'ok' ? 'text-emerald-300 bg-emerald-950/40 border-emerald-900/70' :
                tone === 'err' ? 'text-red-300 bg-red-950/40 border-red-900/70' :
                tone === 'warn' ? 'text-orange-300 bg-orange-950/40 border-orange-900/70' :
                'text-slate-400 bg-slate-900 border-slate-700'
            );
            el.textContent = text;
        }
        if(typeof setScanStatus === 'function'){
            try { setScanStatus(text, tone === 'err' ? 'err' : tone === 'ok' ? 'ok' : tone === 'warn' ? 'warn' : 'info'); } catch(e){}
        }
    }

    function normalizeScannerCode(raw){
        return String(raw || '').replace(/[\r\n\t]/g, '').trim();
    }

    function resolveProductCode(code){
        const clean = normalizeScannerCode(code);
        if(!clean) return '';
        const list = Array.isArray(products) ? products : [];
        const exact = list.find(p => String(p.id).trim() === clean);
        if(exact) return exact.id;
        const upper = clean.toUpperCase();
        const upperMatch = list.find(p => String(p.id).trim().toUpperCase() === upper);
        if(upperMatch) return upperMatch.id;
        return clean;
    }

    function submitScannerGunCode(rawCode, source){
        const code = normalizeScannerCode(rawCode);
        if(!code) return;
        if(!isSalesTabVisible()){
            setGunStatus('扫码枪已读取，但当前不在销售收银页：' + code, 'warn');
            return;
        }
        if(!canUseCashier()){
            setGunStatus('当前账号无权使用扫码枪录入商品。', 'err');
            return;
        }
        if(typeof rebuildProductLookupMap === 'function'){
            try { rebuildProductLookupMap(); } catch(e){}
        }
        const beforeCount = Array.isArray(cart) ? cart.reduce((n, i) => n + (parseInt(i.quantity || 1, 10) || 1), 0) : 0;
        const resolved = resolveProductCode(code);
        if(typeof handleScannedProductId === 'function') handleScannedProductId(resolved);
        const afterCount = Array.isArray(cart) ? cart.reduce((n, i) => n + (parseInt(i.quantity || 1, 10) || 1), 0) : beforeCount;
        if(afterCount > beforeCount){
            const p = (Array.isArray(products) ? products : []).find(x => String(x.id) === String(resolved));
            setGunStatus('扫码枪录入成功：' + (p ? p.name : resolved), 'ok');
            try { if(navigator.vibrate) navigator.vibrate([35, 25, 35]); } catch(e){}
            try { if(typeof playBeepSound === 'function') playBeepSound(); } catch(e){}
        } else {
            setGunStatus('扫码枪未匹配到商品码：' + code, 'err');
        }
        const input = document.getElementById('scanner-gun-input');
        if(input){ input.value = ''; if(source !== 'global') setTimeout(() => input.focus(), 20); }
    }

    function ensureScannerGunUI(){
        if(document.getElementById('scanner-gun-panel')) return;
        const dropdown = document.getElementById('mock-scanner-dropdown');
        if(!dropdown) return;
        const methodB = dropdown.closest('div') && dropdown.closest('div').parentElement;
        const panel = document.createElement('div');
        panel.id = 'scanner-gun-panel';
        panel.className = 'rounded-xl border border-orange-900/50 bg-slate-900/70 p-3 space-y-2';
        panel.innerHTML = `
            <div class="flex items-center justify-between gap-2">
                <label for="scanner-gun-input" class="block text-[10px] text-orange-300 font-bold uppercase tracking-wider">
                    <i class="fa-solid fa-barcode mr-1"></i>方式 C：扫码枪录入
                </label>
                <button type="button" id="scanner-gun-focus-btn" class="text-[10px] px-2 py-1 rounded bg-slate-800 border border-slate-700 text-slate-300 hover:text-orange-300 hover:border-orange-700">聚焦扫码枪</button>
            </div>
            <div class="flex gap-1.5">
                <input type="text" id="scanner-gun-input" autocomplete="off" inputmode="none" placeholder="连接扫码枪后扫描条码/二维码，或粘贴商品码后回车" class="flex-1 bg-slate-950 border border-slate-600 rounded-lg px-2 py-2 text-xs text-slate-100 focus:outline-none focus:border-orange-500 placeholder-slate-500">
                <button type="button" id="scanner-gun-submit-btn" class="bg-orange-500 hover:bg-orange-600 text-slate-950 font-black px-3 py-2 rounded-lg text-xs transition whitespace-nowrap">录入</button>
            </div>
            <div id="scanner-gun-status" class="text-[10px] text-slate-400 bg-slate-900 border border-slate-700 rounded-lg px-2 py-1">支持 USB/蓝牙扫码枪：扫描后自动回车即可加入购物车。</div>
        `;
        if(methodB && methodB.parentElement) methodB.insertAdjacentElement('afterend', panel);
        else dropdown.insertAdjacentElement('afterend', panel);

        const input = document.getElementById('scanner-gun-input');
        const submitBtn = document.getElementById('scanner-gun-submit-btn');
        const focusBtn = document.getElementById('scanner-gun-focus-btn');
        input.addEventListener('keydown', function(e){
            if(e.key === 'Enter' || e.key === 'Tab'){
                e.preventDefault();
                submitScannerGunCode(input.value, 'input');
            }
        });
        submitBtn.addEventListener('click', () => submitScannerGunCode(input.value, 'button'));
        focusBtn.addEventListener('click', () => { input.focus(); input.select(); setGunStatus('扫码枪输入框已聚焦，可以直接扫描。'); });
    }

    function isEditableElement(el){
        if(!el) return false;
        if(el.id === 'scanner-gun-input') return true;
        const tag = (el.tagName || '').toLowerCase();
        return tag === 'input' || tag === 'textarea' || tag === 'select' || el.isContentEditable;
    }

    function resetGunBufferSoon(){
        clearTimeout(gunResetTimer);
        gunResetTimer = setTimeout(() => { gunBuffer = ''; gunLastTime = 0; }, SCANNER_RESET_DELAY);
    }

    document.addEventListener('keydown', function(e){
        if(!isSalesTabVisible() || !canUseCashier()) return;
        const target = e.target;
        if(isEditableElement(target)) return; // 表单内不拦截，扫码枪输入框自己处理 Enter
        if(e.ctrlKey || e.altKey || e.metaKey) return;

        const now = Date.now();
        if(e.key === 'Enter' || e.key === 'Tab'){
            if(gunBuffer.length >= SCANNER_MIN_LEN){
                e.preventDefault();
                const code = gunBuffer;
                gunBuffer = ''; gunLastTime = 0;
                clearTimeout(gunResetTimer);
                submitScannerGunCode(code, 'global');
            }
            return;
        }
        if(e.key && e.key.length === 1){
            if(!gunLastTime || (now - gunLastTime) > SCANNER_MAX_INTERVAL) gunBuffer = '';
            gunBuffer += e.key;
            gunLastTime = now;
            resetGunBufferSoon();
        }
    }, true);

    const oldSwitchTabForGun = window.switchTab;
    if(typeof oldSwitchTabForGun === 'function'){
        window.switchTab = switchTab = function(tabId){
            oldSwitchTabForGun(tabId);
            if(tabId === 'sales-tab') setTimeout(() => { ensureScannerGunUI(); const input = document.getElementById('scanner-gun-input'); if(input && window.innerWidth >= 768) input.focus(); }, 120);
        };
    }

    document.addEventListener('DOMContentLoaded', () => setTimeout(ensureScannerGunUI, 500));
    window.addEventListener('focus', () => setTimeout(ensureScannerGunUI, 150));
    window.__sgScannerGunCheck = function(){
        return {
            enabled: !!document.getElementById('scanner-gun-panel'),
            salesTabVisible: isSalesTabVisible(),
            hasCashierPermission: canUseCashier(),
            productCount: Array.isArray(products) ? products.length : 0,
            cartCount: Array.isArray(cart) ? cart.length : 0,
            hint: '销售收银页聚焦“扫码枪录入”输入框后扫描，或扫码枪以键盘方式快速输入并以 Enter/Tab 结尾。'
        };
    };
})();

/* ===== END assets/js/patches/80-scanner-keyboard-v11.js ===== */


/* ===== BEGIN assets/js/patches/81-mobile-layout-v12.js ===== */
// ===== 手机竖屏 UI 精简与默认收银页 v12 =====
(function(){
    const DEFAULT_TAB = 'sales-tab';
    function preferredTabs(){ return ['sales-tab','product-tab','report-tab','user-tab']; }
    function tabAllowed(tab){
        try{
            const map = {'product-tab':'product_manage','sales-tab':'sales_checkout','report-tab':'report_view','user-tab':'user_manage'};
            return !map[tab] || typeof hasPermission !== 'function' || hasPermission(map[tab]);
        }catch(e){ return tab === 'sales-tab'; }
    }
    function showDefaultSalesTab(){
        if(typeof switchTab === 'function'){
            const target = tabAllowed(DEFAULT_TAB) ? DEFAULT_TAB : (preferredTabs().find(tabAllowed) || DEFAULT_TAB);
            try{ switchTab(target); }catch(e){}
        }
    }
    const oldApplyAuthUICompact = window.applyAuthUI;
    if(typeof oldApplyAuthUICompact === 'function'){
        window.applyAuthUI = applyAuthUI = function(){
            oldApplyAuthUICompact();
            try{
                if(currentUser){
                    const active = document.querySelector('.tab-content:not(.hidden)');
                    if(!active || active.id === 'product-tab') showDefaultSalesTab();
                }
            }catch(e){}
        };
    }

    function ensureMobileCheckoutBar(){
        if(document.getElementById('mobile-bottom-checkout')) return;
        const bar = document.createElement('div');
        bar.id = 'mobile-bottom-checkout';
        bar.className = 'mobile-bottom-checkout';
        bar.innerHTML = `<div class="flex-1 min-w-0"><div class="text-[10px] text-slate-400">应收</div><div id="mobile-cart-total" class="text-xl font-black text-orange-300 truncate">￥0.00</div></div><button onclick="checkoutAndPrint()" class="bg-orange-500 hover:bg-orange-600 text-slate-950 font-black px-5 py-3 rounded-xl text-sm shadow-lg shadow-orange-500/10 whitespace-nowrap"><i class="fa-solid fa-print mr-1"></i>结算</button>`;
        document.body.appendChild(bar);
    }
    function syncMobileTotal(){
        const src = document.getElementById('cart-total-amount');
        const dst = document.getElementById('mobile-cart-total');
        if(src && dst) dst.textContent = src.textContent || '￥0.00';
    }

    window.renderCartTable = renderCartTable = function(){
        const tbody = document.getElementById('cart-table-body');
        if(!tbody) return;
        if(!Array.isArray(cart) || cart.length === 0){
            tbody.innerHTML = `<tr><td colspan="6" class="p-5 text-center text-slate-500">请扫码或搜索加入商品</td></tr>`;
            const total = document.getElementById('cart-total-amount'); if(total) total.innerText = '￥0.00';
            syncMobileTotal();
            return;
        }
        let total = 0;
        tbody.innerHTML = cart.map((item, idx) => {
            const discount = item.discount || 1.0;
            const price = Number(item.product.price || 0);
            const qty = parseInt(item.quantity || 1, 10) || 1;
            const subtotal = price * qty * discount;
            total += subtotal;
            return `
                <tr class="border-b border-slate-700/50 mobile-compact-row">
                    <td class="p-2 font-medium cart-name"><span class="sm:hidden text-slate-500 mr-1">品</span>${item.product.name}</td>
                    <td class="p-2 text-slate-400 sm:table-cell"><span class="sm:hidden text-slate-500 mr-1">价</span>￥${price.toFixed(2)}</td>
                    <td class="p-2 cart-controls sm:table-cell">
                        <select onchange="updateCartDiscount(${idx}, this.value)" class="bg-slate-900 border border-slate-600 rounded text-xs px-1.5 py-1 text-orange-300">
                            ${generateDiscountOptions(discount)}
                        </select>
                        <div class="flex items-center space-x-1.5">
                            <button onclick="updateCartQty(${idx}, -1)" class="w-7 h-7 rounded bg-slate-700 flex items-center justify-center hover:bg-slate-600">-</button>
                            <input type="number" min="1" step="1" inputmode="numeric" pattern="[0-9]*" value="${qty}" onchange="setCartQty(${idx}, this.value)" onblur="setCartQty(${idx}, this.value)" onkeydown="if(event.key==='Enter'){this.blur();}" class="w-14 bg-slate-950 border border-slate-600 rounded px-1 py-1 text-center font-bold text-slate-100 focus:outline-none focus:border-orange-500" title="整数数量">
                            <button onclick="updateCartQty(${idx}, 1)" class="w-7 h-7 rounded bg-slate-700 flex items-center justify-center hover:bg-slate-600">+</button>
                        </div>
                    </td>
                    <td class="p-2 text-orange-300 font-bold cart-subtotal">￥${subtotal.toFixed(2)}</td>
                    <td class="p-2 text-center"><button onclick="cart.splice(${idx},1); renderCartTable();" class="text-red-400 px-2 py-1"><i class="fa-regular fa-trash-can"></i></button></td>
                </tr>`;
        }).join('');
        const totalEl = document.getElementById('cart-total-amount'); if(totalEl) totalEl.innerText = `￥${total.toFixed(2)}`;
        syncMobileTotal();
    };

    function compactDynamicTexts(){
        const gunLabel = document.querySelector('label[for="scanner-gun-input"]');
        if(gunLabel) gunLabel.innerHTML = '<i class="fa-solid fa-barcode mr-1"></i>扫码枪';
        const gunInput = document.getElementById('scanner-gun-input');
        if(gunInput) gunInput.placeholder = '扫码枪扫描或粘贴商品码回车';
        const gunBtn = document.getElementById('scanner-gun-submit-btn');
        if(gunBtn) gunBtn.textContent = '录入';
        const gunFocus = document.getElementById('scanner-gun-focus-btn');
        if(gunFocus) gunFocus.textContent = '聚焦';
        const status = document.getElementById('scanner-gun-status');
        if(status && /USB|蓝牙|扫码枪/.test(status.textContent||'')) status.textContent = '扫码枪输入后自动加入购物车。';
    }
    document.addEventListener('DOMContentLoaded', function(){
        ensureMobileCheckoutBar();
        setTimeout(showDefaultSalesTab, 250);
        setTimeout(function(){ if(typeof renderCartTable === 'function') renderCartTable(); compactDynamicTexts(); }, 650);
    });
    window.addEventListener('focus', function(){ setTimeout(function(){ ensureMobileCheckoutBar(); compactDynamicTexts(); syncMobileTotal(); }, 200); });
    const oldSwitchTabCompact = window.switchTab;
    if(typeof oldSwitchTabCompact === 'function'){
        window.switchTab = switchTab = function(tabId){
            oldSwitchTabCompact(tabId);
            setTimeout(function(){ compactDynamicTexts(); syncMobileTotal(); }, 80);
        };
    }
    window.__sgMobileUICheck = function(){ return {defaultTab:'sales-tab', activeTab:(document.querySelector('.tab-content:not(.hidden)')||{}).id, compactMobileUI:true, manualBusinessSyncUI:false}; };
})();

/* ===== END assets/js/patches/81-mobile-layout-v12.js ===== */


/* ===== BEGIN assets/js/patches/82-admin-clear-sales.js ===== */
// ===== 管理员销售记录清除功能 v1：密码复核 + 删除墓碑 =====
(function(){
    const BUTTON_ID = 'admin-clear-sales-btn';
    const nowIso = () => new Date().toISOString();
    const arr = v => Array.isArray(v) ? v : [];

    function liveAdmin(){
        try {
            if (!currentUser) return null;
            const u = arr(users).find(x => x && (x.id === currentUser.id || x.username === currentUser.username));
            return u && u.role === 'admin' && u.status !== 'disabled' ? u : null;
        } catch(e) { return null; }
    }

    function refreshAdminClearSalesButton(){
        const btn = document.getElementById(BUTTON_ID);
        if (!btn) return;
        btn.classList.toggle('hidden', !liveAdmin());
    }

    async function recordFailure(admin){
        try {
            if (typeof addAudit === 'function') addAudit('清除销售记录失败', '全部销售记录', '管理员密码校验失败');
            if (typeof saveAllLocal === 'function') saveAllLocal();
            if (typeof pushToCloud === 'function') await pushToCloud();
        } catch(e) {}
    }

    window.clearAllSalesRecordsByAdmin = async function(){
        const admin = liveAdmin();
        if (!admin) return alert('仅启用状态的管理员账户可以清除销售记录。');
        const password = prompt('请输入当前管理员密码，以确认清除全部销售记录：');
        if (password === null) return;
        if (!password) return alert('未输入密码，操作已取消。');
        let passed = false;
        try { passed = typeof verifyPassword === 'function' && await verifyPassword(admin, password); } catch(e) {}
        if (!passed) {
            await recordFailure(admin);
            return alert('管理员密码错误，未清除任何销售记录。');
        }
        const cleanOrders = arr(orders).filter(o => o && o.id && o.id !== '__SG_CLOUD_STATE__' && o.__syncMeta !== true);
        const count = cleanOrders.length;
        if (!count) return alert('当前没有可清除的销售记录。');
        if (!confirm('危险操作：即将永久清除全部 ' + count + ' 条销售记录。\n\n商品、库存、用户与审计日志不会被删除。\n\n确定继续吗？')) return;
        try {
            for (const order of cleanOrders) {
                if (typeof window.__sgAddTombstone === 'function') window.__sgAddTombstone('orders', order.id);
            }
            orders = [];
            try { syncVersion = (parseInt(syncVersion || 0, 10) || 0) + 1; } catch(e) {}
            try { localStorage.setItem('sg_orders', JSON.stringify([])); } catch(e) {}
            if (typeof addAudit === 'function') addAudit('清除销售记录', '全部销售记录', '管理员确认清除 ' + count + ' 条订单；已写入订单删除标记');
            if (typeof saveAllLocal === 'function') saveAllLocal();
            try { if (typeof updateReportDashboard === 'function') updateReportDashboard(); } catch(e) {}
            try { if (typeof renderLedgerTable === 'function') renderLedgerTable(); } catch(e) {}
            let synced = false;
            try { if (typeof pushToCloud === 'function') synced = await pushToCloud(); } catch(e) {}
            try { if (typeof window.__sgScheduleAutoSync === 'function') window.__sgScheduleAutoSync('admin-clear-sales', 350); } catch(e) {}
            alert(synced || !navigator.onLine
                ? (navigator.onLine ? '已清除 ' + count + ' 条销售记录，并提交自动云同步。' : '已在本机清除 ' + count + ' 条销售记录；联网后会自动同步删除标记。')
                : '已清除 ' + count + ' 条销售记录。云同步暂未完成，系统会自动重试。');
        } catch(e) {
            console.error('清除销售记录失败：', e);
            alert('清除销售记录失败：' + (e && e.message ? e.message : String(e)));
        }
    };

    window.refreshAdminClearSalesButton = refreshAdminClearSalesButton;
    const oldApplyAuth = window.applyAuthUI;
    if (typeof oldApplyAuth === 'function') {
        window.applyAuthUI = applyAuthUI = function(){
            const r = oldApplyAuth.apply(this, arguments);
            refreshAdminClearSalesButton();
            return r;
        };
    }
    document.addEventListener('DOMContentLoaded', () => setTimeout(refreshAdminClearSalesButton, 450));
    window.addEventListener('focus', () => setTimeout(refreshAdminClearSalesButton, 120));
    console.info('管理员销售记录清除功能已加载：password-confirm + order-tombstones');
})();

/* ===== END assets/js/patches/82-admin-clear-sales.js ===== */


// ===== Refactor bridge: password self-service retained from retired sync v5 patch =====
(function(){
  function nowIso(){ return new Date().toISOString(); }
  window.changeOwnPassword = changeOwnPassword = async function(e){
    e.preventDefault();
    if (!currentUser) return alert('请先登录。');
    const oldInput = document.getElementById('own-old-password');
    const newInput = document.getElementById('own-new-password');
    const oldP = oldInput ? oldInput.value : '';
    const newP = newInput ? newInput.value : '';
    if (!newP || newP.length < 6) return alert('新密码至少 6 位。');
    const u = (users || []).find(x => x.id === currentUser.id || x.username === currentUser.username);
    if (!u) return alert('当前账号不存在，请重新登录。');
    if (!(await verifyPassword(u, oldP))) return alert('当前密码不正确。');
    const hp = await hashPassword(newP);
    u.passwordSalt = hp.salt;
    u.passwordHash = hp.hash;
    delete u.password;
    u.updatedAt = nowIso();
    syncVersion = (parseInt(syncVersion || '0', 10) || 0) + 1;
    if (typeof saveAllLocal === 'function') saveAllLocal();
    try { addAudit('修改密码', u.username, '当前账号自行修改'); } catch(err) {}
    if (typeof pushToCloud === 'function') await pushToCloud();
    if (e && e.target && typeof e.target.reset === 'function') e.target.reset();
    alert('密码已更新，并已加入云端同步。');
  };
})();


/* ===== BEGIN assets/js/v3-enhancements.js ===== */
/* 第二引力销售系统 V3 Enhancement Layer
   不改变原有数据结构，增加体验、安全提示、安装与更新流程。 */
(function () {
  'use strict';

  const VERSION = '3.0.0';
  const state = { deferredInstallPrompt: null };

  function $(id) { return document.getElementById(id); }

  function ensureToastStack() {
    let stack = $('v3-toast-stack');
    if (!stack) {
      stack = document.createElement('div');
      stack.id = 'v3-toast-stack';
      stack.setAttribute('aria-live', 'polite');
      document.body.appendChild(stack);
    }
    return stack;
  }

  function toast(message, type = 'info', title = '') {
    const stack = ensureToastStack();
    const node = document.createElement('div');
    node.className = `v3-toast ${type}`;
    const icon = type === 'success' ? '✓' : type === 'error' ? '!' : type === 'warning' ? '⚠' : 'i';
    node.innerHTML = `<div class="v3-toast-icon">${icon}</div><div><div class="v3-toast-title">${title || labelOf(type)}</div><div class="v3-toast-message"></div></div><button type="button" aria-label="关闭通知">×</button>`;
    node.querySelector('.v3-toast-message').textContent = String(message || '');
    node.querySelector('button').addEventListener('click', () => node.remove());
    stack.appendChild(node);
    window.setTimeout(() => node.remove(), type === 'error' ? 6200 : 3800);
  }

  function labelOf(type) {
    return ({ success: '操作成功', error: '需要处理', warning: '注意', info: '提示' })[type] || '提示';
  }

  // 用非阻塞 Toast 替代多数 alert，保留 confirm 的确认语义。
  const nativeAlert = window.alert;
  window.alert = function (message) {
    toast(message, /错误|失败|没有权限|停用/.test(String(message)) ? 'error' : 'warning');
    console.warn('[V3 alert intercepted]', message);
  };
  window.v3Toast = toast;
  window.v3NativeAlert = nativeAlert;

  function createSyncIndicator() {
    if ($('v3-sync-indicator')) return;
    const indicator = document.createElement('div');
    indicator.id = 'v3-sync-indicator';
    indicator.innerHTML = '<span class="v3-dot"></span><span>云端同步中</span>';
    document.body.appendChild(indicator);
  }

  function decorateNetworkStatus() {
    const badge = document.createElement('div');
    badge.className = 'v3-status-pill';
    badge.id = 'v3-network-pill';
    badge.style.position = 'fixed';
    badge.style.left = '14px';
    badge.style.bottom = 'calc(18px + env(safe-area-inset-bottom))';
    badge.style.zIndex = '72';
    document.body.appendChild(badge);
    const update = () => {
      const online = navigator.onLine;
      badge.classList.toggle('online', online);
      badge.classList.toggle('offline', !online);
      badge.textContent = online ? '在线 · 自动同步' : '离线 · 本地暂存';
    };
    window.addEventListener('online', () => { update(); toast('网络已恢复，数据会继续同步。', 'success'); });
    window.addEventListener('offline', () => { update(); toast('当前离线，销售数据仍会保存在本机。', 'warning'); });
    update();
  }

  function decorateInstallPrompt() {
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.id = 'v3-install-fab';
    btn.className = 'v3-fab';
    btn.innerHTML = '<span>⬇</span><span>安装应用</span>';
    document.body.appendChild(btn);
    window.addEventListener('beforeinstallprompt', (event) => {
      event.preventDefault();
      state.deferredInstallPrompt = event;
      btn.classList.add('show');
    });
    btn.addEventListener('click', async () => {
      if (!state.deferredInstallPrompt) return toast('当前浏览器暂未开放安装入口，可在浏览器菜单中选择“添加到主屏幕”。', 'info');
      state.deferredInstallPrompt.prompt();
      await state.deferredInstallPrompt.userChoice.catch(() => null);
      state.deferredInstallPrompt = null;
      btn.classList.remove('show');
    });
  }

  function strengthenDefaultAdminWarning() {
    try {
      const users = JSON.parse(localStorage.getItem('sg_users') || '[]');
      const weak = users.some(u => u.username === 'admin' && u.password === 'admin123');
      if (weak) toast('检测到默认管理员密码 admin123。上线前请在“用户管理”中立即修改。', 'warning', '安全提醒');
    } catch (_) {}
  }

  function addKeyboardShortcuts() {
    document.addEventListener('keydown', (event) => {
      if (event.altKey || event.metaKey || event.ctrlKey) return;
      if (['INPUT', 'TEXTAREA', 'SELECT'].includes(document.activeElement?.tagName)) return;
      const map = { '1': 'product-tab', '2': 'sales-tab', '3': 'report-tab', '4': 'user-tab' };
      if (map[event.key] && typeof window.switchTab === 'function') {
        event.preventDefault();
        window.switchTab(map[event.key]);
      }
      if (event.key === '/' && $('product-search')) {
        event.preventDefault();
        $('product-search').focus();
      }
    });
  }

  function wrapCloudSyncIndicators() {
    createSyncIndicator();
    const indicator = $('v3-sync-indicator');
    ['syncFromCloud', 'pushToCloud'].forEach(name => {
      const original = window[name];
      if (typeof original !== 'function') return;
      window[name] = async function (...args) {
        indicator.classList.add('active');
        try { return await original.apply(this, args); }
        finally { window.setTimeout(() => indicator.classList.remove('active'), 280); }
      };
    });
  }

  function registerServiceWorkerUpdateUX() {
    if (!('serviceWorker' in navigator)) return;
    navigator.serviceWorker.addEventListener('controllerchange', () => {
      toast('应用已更新到新版。刷新后即可使用最新缓存。', 'success', '更新完成');
    });
  }

  function markVersion() {
    document.documentElement.dataset.appVersion = VERSION;
    const badge = document.createElement('span');
    badge.className = 'v3-status-pill';
    badge.textContent = `V${VERSION}`;
    const header = document.querySelector('header .max-w-7xl, header');
    if (header) header.appendChild(badge);
  }

  window.addEventListener('load', () => {
    ensureToastStack();
    createSyncIndicator();
    decorateNetworkStatus();
    decorateInstallPrompt();
    addKeyboardShortcuts();
    wrapCloudSyncIndicators();
    registerServiceWorkerUpdateUX();
    markVersion();
    strengthenDefaultAdminWarning();
    toast('V3 体验增强层已启用：移动端 UI、Toast、安装提示、离线状态和快捷键。', 'success', '欢迎使用');
  });
})();

/* ===== END assets/js/v3-enhancements.js ===== */
